import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Department {
  HOSTEL = 'Hostel',
  MESS = 'Mess/Food',
  ACADEMICS = 'Academics',
  ADMINISTRATION = 'Administration',
  HYGIENE = 'Hygiene',
  ELECTRICAL = 'Electrical',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export enum Status {
  SUBMITTED = 'Submitted',
  IN_REVIEW = 'In Review',
  ASSIGNED = 'Assigned',
  IN_PROGRESS = 'In Progress',
  RESOLVED = 'Resolved',
  CLOSED = 'Closed'
}

export interface Grievance {
  id: string;
  timestamp: number;
  description: string;
  department: Department;
  severity: Severity;
  status: Status;
  isAnonymous: boolean;
  contactInfo?: string;
  history: { status: Status; timestamp: number; remark?: string }[];
  remarks: string[];
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

export enum UserRole {
  USER = 'user',
  STAFF = 'staff',
  ADMIN = 'admin'
}

import React from 'react';

