import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

const API_KEY = process.env.API_KEY;

export const classifyGrievance = async (text: string) => {
  if (!API_KEY) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Classify the following educational institution grievance: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          department: {
            type: Type.STRING,
            description: "One of: Hostel, Mess/Food, Academics, Administration, Hygiene, Electrical, Other",
          },
          severity: {
            type: Type.STRING,
            description: "One of: Low, Medium, High, Critical",
          },
          empatheticResponse: {
            type: Type.STRING,
            description: "A short, supportive acknowledging response for the user.",
          },
          summary: {
            type: Type.STRING,
            description: "A one-sentence professional summary of the issue.",
          }
        },
        required: ["department", "severity", "empatheticResponse", "summary"],
      },
    },
  });

  return JSON.parse(response.text);
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  if (!API_KEY) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));

  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are EduResolve Assistant, a helpful bot for an educational institution's grievance system. Be empathetic, objective, and professional. Ask for details if the grievance description is too short. If they are ready to submit, explain that their identity is safe.",
    },
  });

  return response.text;
};

import { Grievance, Status } from './types';

const STORAGE_KEY = 'eduresolve_grievances';

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();
  const updated = [...current, grievance];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
};

export const updateGrievanceStatus = (id: string, newStatus: Status, remark?: string) => {
  const current = getGrievances();
  const updated = current.map(g => {
    if (g.id === id) {
      const historyEntry = { status: newStatus, timestamp: Date.now(), remark };
      return {
        ...g,
        status: newStatus,
        history: [...g.history, historyEntry],
        remarks: remark ? [...g.remarks, remark] : g.remarks
      };
    }
    return g;
  });
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
};

export const findGrievanceById = (id: string) => {
  return getGrievances().find(g => g.id === id);
};

