import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { getBotResponse, classifyGrievance } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance } from '../store';

const GrievanceChatbot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: "Hello! I'm EduResolve AI. How can I help you today? You can describe any grievance or concern you have regarding the institution." }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [submittedGrievance, setSubmittedGrievance] = useState<Grievance | null>(null);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsTyping(true);

    try {
      // If the message seems like a full grievance, we trigger classification logic
      // For this demo, we check if it's longer than 20 chars
      if (userMessage.length > 20 && messages.length >= 1) {
        const classification = await classifyGrievance(userMessage);

        const botResponse = classification.empatheticResponse;
        setMessages(prev => [...prev, { role: 'assistant', content: botResponse }]);

        // Generate a real grievance entry
        const grievanceId = 'GRV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
        const newGrievance: Grievance = {
          id: grievanceId,
          timestamp: Date.now(),
          description: userMessage,
          department: classification.department as Department,
          severity: classification.severity as Severity,
          status: Status.SUBMITTED,
          isAnonymous: isAnonymous,
          history: [{ status: Status.SUBMITTED, timestamp: Date.now() }],
          remarks: []
        };

        saveGrievance(newGrievance);
        setSubmittedGrievance(newGrievance);

        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: `I've successfully registered your grievance. Reference ID: **${grievanceId}**. It has been classified under ${classification.department} with ${classification.severity} priority.` 
        }]);
      } else {
        const response = await getBotResponse(messages, userMessage);
        setMessages(prev => [...prev, { role: 'assistant', content: response }]);
      }
    } catch (err) {
      setMessages(prev => [...prev, { role: 'assistant', content: "I'm having a bit of trouble connecting to my brain. Please try again in a moment." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto flex flex-col h-[calc(100vh-12rem)]">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 flex-1 flex flex-col overflow-hidden">
        {/* Chat Header */}
        <div className="p-4 border-b bg-slate-50 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="font-semibold text-slate-800">Grievance Assistant</h2>
              <span className="text-xs text-emerald-500 flex items-center gap-1">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                AI Agent Online
              </span>
            </div>
          </div>
          <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border text-xs">
            <span className="text-slate-500">Anonymous Mode:</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-10 h-5 rounded-full transition-colors relative ${isAnonymous ? 'bg-indigo-600' : 'bg-slate-200'}`}
            >
              <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${isAnonymous ? 'left-6' : 'left-1'}`}></div>
            </button>
          </div>
        </div>

        {/* Message Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-600'}`}>
                  {msg.role === 'user' ? <ICONS.User /> : <ICONS.Bot />}
                </div>
                <div className={`p-4 rounded-2xl shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-slate-100 text-slate-800 rounded-tl-none'
                }`}>
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                </div>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="flex gap-3 items-center">
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center text-slate-600">
                  <ICONS.Bot />
                </div>
                <div className="flex gap-1">
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            </div>
          )}
          <div ref={scrollRef}></div>
        </div>

        {/* Submission Summary Card (Floating when resolved) */}
        {submittedGrievance && (
          <div className="p-4 bg-emerald-50 border-t border-emerald-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
             <div className="flex items-start gap-3">
               <div className="bg-emerald-100 p-2 rounded-lg">
                 <svg className="w-5 h-5 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                 </svg>
               </div>
               <div className="flex-1">
                 <h4 className="font-bold text-emerald-900 text-sm">Grievance Registered</h4>
                 <p className="text-xs text-emerald-700 mt-1">Ref ID: <span className="font-mono bg-white px-1 border rounded">{submittedGrievance.id}</span></p>
                 <p className="text-xs text-emerald-600 mt-1 italic">Save this ID to track your progress later.</p>
               </div>
               <button 
                onClick={() => setSubmittedGrievance(null)}
                className="text-emerald-500 hover:text-emerald-700"
               >
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                 </svg>
               </button>
             </div>
          </div>
        )}

        {/* Input Area */}
        <div className="p-4 bg-white border-t">
          <form onSubmit={handleSubmit} className="flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Type your concern here..."
              className="flex-1 bg-slate-100 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              disabled={isTyping}
            />
            <button
              type="submit"
              disabled={!input.trim() || isTyping}
              className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
          <p className="text-[10px] text-center text-slate-400 mt-2">
            Your conversations are analyzed by AI to help resolve issues faster. 
            {isAnonymous ? " Identity is currently hidden." : " Identity will be shared with authorities."}
          </p>
        </div>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import React, { useState } from 'react';
import { findGrievanceById } from '../store';
import { Grievance, Status } from '../types';
import { COLORS } from '../constants';

const GrievanceTracker: React.FC = () => {
  const [searchId, setSearchId] = useState('');
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [error, setError] = useState('');

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    const found = findGrievanceById(searchId.trim());
    if (found) {
      setGrievance(found);
      setError('');
    } else {
      setGrievance(null);
      setError('No grievance found with this ID.');
    }
  };

  const statusSteps: Status[] = [
    Status.SUBMITTED,
    Status.IN_REVIEW,
    Status.ASSIGNED,
    Status.IN_PROGRESS,
    Status.RESOLVED,
    Status.CLOSED,
  ];

  const getStepIndex = (status: Status) => statusSteps.indexOf(status);

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="text-center space-y-2 mb-8">
        <h2 className="text-3xl font-bold text-slate-900">Track Your Grievance</h2>
        <p className="text-slate-500">Enter your unique reference ID to see live updates.</p>
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <form onSubmit={handleSearch} className="flex gap-2">
          <input
            type="text"
            value={searchId}
            onChange={(e) => setSearchId(e.target.value)}
            placeholder="e.g. GRV-K9W2J4"
            className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button
            type="submit"
            className="bg-slate-900 text-white px-6 rounded-xl hover:bg-slate-800 transition-colors"
          >
            Track
          </button>
        </form>
        {error && <p className="text-red-500 text-sm mt-2">{error}</p>}
      </div>

      {grievance && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-4">
          <div className="p-6 border-b bg-slate-50 flex justify-between items-center">
            <div>
              <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Ref ID</span>
              <h3 className="text-xl font-bold text-slate-900 font-mono">{grievance.id}</h3>
            </div>
            <div className={`px-4 py-1.5 rounded-full text-xs font-bold ${COLORS.status[grievance.status]}`}>
              {grievance.status}
            </div>
          </div>

          <div className="p-6 space-y-8">
            {/* Timeline Progress */}
            <div className="relative">
              <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-100 -translate-y-1/2"></div>
              <div className="relative flex justify-between">
                {statusSteps.map((step, idx) => {
                  const currentIdx = getStepIndex(grievance.status);
                  const isCompleted = idx <= currentIdx;
                  const isCurrent = idx === currentIdx;

                  return (
                    <div key={step} className="flex flex-col items-center gap-2 relative">
                      <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center text-xs font-bold transition-all z-10 ${
                        isCompleted 
                          ? 'bg-indigo-600 border-indigo-100 text-white' 
                          : 'bg-white border-slate-100 text-slate-300'
                      } ${isCurrent ? 'ring-4 ring-indigo-100 scale-110' : ''}`}>
                        {idx + 1}
                      </div>
                      <span className={`text-[10px] absolute top-10 whitespace-nowrap font-medium ${
                        isCompleted ? 'text-indigo-600' : 'text-slate-400'
                      }`}>
                        {step}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="mt-16 grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
              <div className="space-y-4">
                <div>
                  <h4 className="text-sm font-semibold text-slate-500 mb-1">Department</h4>
                  <span className={`px-3 py-1 rounded-lg text-xs font-medium ${COLORS.department[grievance.department]}`}>
                    {grievance.department}
                  </span>
                </div>
                <div>
