import { Grievance, Status, User, UserRole, Department } from './types';

const GRIEVANCE_KEY = 'eduresolve_grievances';
const USER_KEY = 'eduresolve_current_user';

// Mock Data
export const MOCK_USERS: User[] = [
  { id: 'STU-01', name: 'John Student', role: UserRole.STUDENT },
  { id: 'INC-01', name: 'Dr. Smith (Class A)', role: UserRole.INCHARGE },
  { id: 'STAFF-MESS', name: 'Chef Gordon', role: UserRole.STAFF, department: Department.MESS },
  { id: 'STAFF-ELEC', name: 'Sparky Mike', role: UserRole.STAFF, department: Department.ELECTRICAL },
  { id: 'ADM-01', name: 'Principal Director', role: UserRole.ADMIN },
];

export const getCurrentUser = (): User => {
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : MOCK_USERS[0];
};

export const setCurrentUser = (user: User) => {
  localStorage.setItem(USER_KEY, JSON.stringify(user));
  window.dispatchEvent(new Event('storage')); // Trigger update
};

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(GRIEVANCE_KEY);
  return data ? JSON.parse(data) : [];
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();
  const updated = [...current, grievance];
  localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(updated));
};

export const updateGrievance = (updatedG: Grievance) => {
  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

export const findGrievanceById = (id: string) => {
  return getGrievances().find(g => g.id === id);
};

