import React, { useState, useMemo, useEffect } from 'react';
import { getGrievances, updateGrievance, getCurrentUser, MOCK_USERS } from '../store';
import { Grievance, Status, UserRole, Department, User } from '../types';
import { COLORS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const ManagementConsole: React.FC = () => {
  const [grievances, setGrievances] = useState<Grievance[]>(getGrievances());
  const [selectedGrievance, setSelectedGrievance] = useState<Grievance | null>(null);
  const [remarkInput, setRemarkInput] = useState('');
  const [statusInput, setStatusInput] = useState<Status | ''>('');
  const [delegateStaffId, setDelegateStaffId] = useState('');
  const currentUser = getCurrentUser();

  const refreshData = () => setGrievances(getGrievances());

  // Logic: In-charge sees their class grievances. Staff sees grievances assigned to them. Admins see all.
  const filtered = useMemo(() => {
    if (currentUser.role === UserRole.ADMIN) return grievances;
    if (currentUser.role === UserRole.INCHARGE) return grievances.filter(g => g.inChargeId === currentUser.id);
    if (currentUser.role === UserRole.STAFF) return grievances.filter(g => g.assignedStaffId === currentUser.id);
    return [];
  }, [grievances, currentUser]);

  const stats = useMemo(() => {
    const counts = { pending: 0, critical: 0, resolved: 0 };
    filtered.forEach(g => {
      if (g.status === Status.RESOLVED || g.status === Status.CLOSED) counts.resolved++;
      else counts.pending++;
      if (g.severity === 'Critical') counts.critical++;
    });
    return counts;
  }, [filtered]);

  const handleUpdate = () => {
    if (!selectedGrievance) return;

    const updated = { ...selectedGrievance };
    const now = Date.now();

    if (statusInput) {
      updated.status = statusInput as Status;
      updated.lastStatusChange = now;
      updated.history.push({ status: updated.status, timestamp: now, userId: currentUser.id, remark: remarkInput });
      if (remarkInput) updated.remarks.push(remarkInput);
    }

    if (delegateStaffId && currentUser.role === UserRole.INCHARGE) {
      updated.assignedStaffId = delegateStaffId;
      updated.status = Status.ASSIGNED;
      updated.history.push({ status: Status.ASSIGNED, timestamp: now, userId: currentUser.id, remark: "Delegated to department staff." });
    }

    updateGrievance(updated);
    setSelectedGrievance(null);
    setRemarkInput('');
    setStatusInput('');
    setDelegateStaffId('');
    refreshData();
  };

  const isEscalated = (g: Grievance) => {
    // Escalate if status is In Progress and hasn't changed for 5 mins (demo time)
    const threshold = 5 * 60 * 1000;
    return g.status === Status.IN_PROGRESS && (Date.now() - g.lastStatusChange) > threshold;
  };

  // Only In-charge or assigned Staff can modify status
  const canUpdateStatus = (g: Grievance) => {
    if (currentUser.role === UserRole.ADMIN) return false;
    if (currentUser.role === UserRole.INCHARGE && g.inChargeId === currentUser.id) return true;
    if (currentUser.role === UserRole.STAFF && g.assignedStaffId === currentUser.id) return true;
    return false;
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Grievance Management</h2>
          <p className="text-slate-500">Logged in as {currentUser.name} ({currentUser.role})</p>
        </div>
        <div className="flex gap-4">
           <div className="bg-white p-4 rounded-xl border shadow-sm">
             <span className="text-[10px] uppercase font-bold text-slate-400">Tickets</span>
             <p className="text-xl font-bold text-indigo-600">{filtered.length}</p>
           </div>
           <div className="bg-red-50 p-4 rounded-xl border border-red-100 shadow-sm">
             <span className="text-[10px] uppercase font-bold text-red-400">Critical</span>
             <p className="text-xl font-bold text-red-600">{stats.critical}</p>
           </div>
        </div>
      </div>

      {/* Grid of Tickets */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.map(g => (
          <div key={g.id} className={`bg-white rounded-2xl border p-6 shadow-sm hover:shadow-md transition-all relative overflow-hidden ${isEscalated(g) ? 'ring-2 ring-red-400' : ''}`}>
            {isEscalated(g) && (
