            <select 
              value={filterDept}
              onChange={(e) => setFilterDept(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-1.5 text-xs focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              <option value="All">All Departments</option>
              {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
