const ProtectedRoute: React.FC<{ children: React.ReactNode; roles?: UserRole[] }> = ({ children, roles }) => {
  if (!isAuthenticated()) {
    return <Navigate to="/login" replace />;
  }

  const user = getCurrentUser();
  if (roles && user && !roles.includes(user.role)) {
    return <Navigate to={user.role === UserRole.STUDENT ? "/" : "/dashboard"} replace />;
  }

  return <>{children}</>;
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/login" element={<Login />} />

          <Route path="/" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceChatbot />
            </ProtectedRoute>
          } />

          <Route path="/track" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceTracker />
            </ProtectedRoute>
          } />

          <Route path="/dashboard" element={
            <ProtectedRoute roles={[UserRole.INCHARGE, UserRole.STAFF, UserRole.ADMIN]}>
              <ManagementConsole />
            </ProtectedRoute>
          } />

          <Route path="/admin-view" element={
            <ProtectedRoute roles={[UserRole.ADMIN]}>
              <AdminDashboard />
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

