  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    // Delivery-style notification simulation
    const oldStatus = current[index].status;
    if (oldStatus !== updatedG.status) {
      updatedG.notificationsSent.push({
        type: 'email',
        timestamp: Date.now(),
        message: `Status update: Your grievance #${updatedG.id} has moved from ${oldStatus} to ${updatedG.status}.`
      });
    }
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

