          id: grievanceId,
          timestamp: now,
          description: userMessage,
          department: dept,
          severity: classification.severity as Severity,
          status: Status.SUBMITTED,
          isAnonymous: isAnonymous,
          studentId: currentUser?.id || 'ANON',
          assignedToId: assignedStaffId, 
          lastStatusChange: now,
          history: [{ status: Status.SUBMITTED, timestamp: now, userId: currentUser?.id || 'ANON' }],
          remarks: [],
          notificationsSent: [{
            type: 'email',
            timestamp: now,
            message: `Grievance registered. Ref: ${grievanceId}. It is routed to ${staffName}.`
          }]
        };

        saveGrievance(newGrievance);
        setSubmittedGrievance(newGrievance);

        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: `${classification.empatheticResponse}\n\nI have routed your complaint to **${staffName}** (${dept}). You will receive an email notification for every status update.` 
        }]);
      } else {
        const response = await getBotResponse(messages, userMessage);
        setMessages(prev => [...prev, { role: 'assistant', content: response }]);
      }
    } catch (err) {
      setMessages(prev => [...prev, { role: 'assistant', content: "I'm having trouble processing that. Can you try rephrasing?" }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto flex flex-col h-[calc(100vh-12rem)]">
      <div className="bg-white rounded-3xl shadow-xl border border-slate-200 flex-1 flex flex-col overflow-hidden">
        <div className="p-5 border-b bg-indigo-600 flex items-center justify-between text-white">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/20 rounded-2xl flex items-center justify-center">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="font-bold">EduResolve Assistant</h2>
              <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full uppercase tracking-widest font-bold">NLP Processor</span>
            </div>
          </div>
          <div className="flex items-center gap-2 bg-white/10 px-3 py-1.5 rounded-xl border border-white/20 text-xs">
            <span className="font-medium">Anonymity:</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-10 h-5 rounded-full transition-all relative ${isAnonymous ? 'bg-emerald-400' : 'bg-white/20'}`}
            >
              <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${isAnonymous ? 'left-6' : 'left-1'}`}></div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`p-4 rounded-2xl shadow-sm text-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-slate-100 text-slate-800 rounded-tl-none'
                }`}>
                  {msg.content}
                </div>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start items-center gap-2">
              <div className="flex gap-1 bg-slate-100 p-3 rounded-2xl">
                <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></span>
                <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.1s]"></span>
                <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              </div>
            </div>
          )}
          <div ref={scrollRef}></div>
        </div>

        {submittedGrievance && (
          <div className="px-6 py-4 bg-emerald-50 border-t border-emerald-100 flex items-center justify-between">
            <div className="flex gap-3">
              <div className="w-8 h-8 bg-emerald-100 rounded-lg flex items-center justify-center text-emerald-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
              </div>
              <div>
                <p className="text-xs font-bold text-emerald-900">Reference: {submittedGrievance.id}</p>
                <p className="text-[10px] text-emerald-600">Saved to track history. Check 'My Grievances'.</p>
              </div>
            </div>
            <button onClick={() => setSubmittedGrievance(null)} className="text-emerald-500 font-bold text-xs uppercase">Dismiss</button>
          </div>
        )}

        <div className="p-4 bg-white border-t">
          <form onSubmit={handleSubmit} className="flex gap-3">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="E.g., I have an issue with the hostel wifi..."
              className="flex-1 bg-slate-50 border-slate-200 border rounded-2xl px-5 py-3.5 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              disabled={isTyping}
            />
            <button
              type="submit"
              disabled={!input.trim() || isTyping}
              className="bg-indigo-600 text-white px-6 rounded-2xl hover:bg-indigo-700 transition-all shadow-lg disabled:opacity-50"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import React, { useState } from 'react';
