import React, { useState, useMemo } from 'react';
import { getGrievances, updateGrievance, getCurrentUser } from '../store';
import { Grievance, Status, UserRole } from '../types';
import { COLORS } from '../constants';

const ManagementConsole: React.FC = () => {
  const [grievances, setGrievances] = useState<Grievance[]>(getGrievances());
  const [selectedGrievance, setSelectedGrievance] = useState<Grievance | null>(null);
  const [remarkInput, setRemarkInput] = useState('');
  const [statusInput, setStatusInput] = useState<Status | ''>('');
  const currentUser = getCurrentUser();

  const refreshData = () => setGrievances(getGrievances());

  // Logic: Staff see only what's assigned to their specific staff ID. Admin sees everything.
  const filtered = useMemo(() => {
    if (!currentUser) return [];
    if (currentUser.role === UserRole.ADMIN) return grievances;
    return grievances.filter(g => g.assignedToId === currentUser.id);
  }, [grievances, currentUser]);

  const handleUpdate = () => {
    if (!selectedGrievance || !currentUser) return;

    const updated = { ...selectedGrievance };
    const now = Date.now();

    if (statusInput) {
      updated.status = statusInput as Status;
      updated.lastStatusChange = now;
      updated.history.push({ status: updated.status, timestamp: now, userId: currentUser.id, remark: remarkInput });
      if (remarkInput) updated.remarks.push(remarkInput);
    }

    updateGrievance(updated);
    setSelectedGrievance(null);
    setRemarkInput('');
    setStatusInput('');
    refreshData();
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Department Dashboard</h2>
          <p className="text-slate-500 font-medium">Monitoring: {currentUser?.department || 'Institution-wide'}</p>
        </div>
        <div className="flex gap-4">
           <div className="bg-white p-5 rounded-3xl border shadow-sm">
             <span className="text-[10px] uppercase font-bold text-slate-400 block mb-1">Queue Size</span>
             <p className="text-2xl font-black text-indigo-600">{filtered.filter(g => g.status !== Status.RESOLVED).length}</p>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filtered.map(g => (
          <div key={g.id} className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm hover:shadow-xl transition-all group">
            <div className="flex justify-between items-start mb-4">
              <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-widest">{g.department}</span>
              <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${COLORS.status[g.status]}`}>{g.status}</span>
            </div>
            <h3 className="font-bold text-slate-900 mb-2">Complaint #{g.id}</h3>
            <p className="text-sm text-slate-600 line-clamp-2 mb-6 leading-relaxed italic">"{g.description}"</p>

            <div className="flex items-center justify-between pt-4 border-t border-slate-50">
              <span className={`text-[10px] font-bold px-3 py-1 rounded-full ${COLORS.severity[g.severity]}`}>{g.severity} Priority</span>
              <button 
                onClick={() => setSelectedGrievance(g)}
                className="bg-slate-900 text-white text-xs px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-slate-200 hover:scale-105 transition-all"
              >
                Resolve
              </button>
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="col-span-full py-32 text-center bg-white rounded-3xl border-2 border-dashed border-slate-200">
             <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
               <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             </div>
             <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Your queue is currently clear</p>
          </div>
        )}
      </div>

      {selectedGrievance && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-8 border-b flex justify-between items-center">
              <div>
                <h4 className="font-black text-slate-900 text-xl">Addressing #{selectedGrievance.id}</h4>
                <p className="text-xs text-slate-500 font-medium">Department: {selectedGrievance.department}</p>
              </div>
              <button onClick={() => setSelectedGrievance(null)} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center hover:bg-slate-100 transition-all">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="p-10 space-y-8 max-h-[75vh] overflow-y-auto">
              <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                <p className="text-[10px] uppercase font-black text-indigo-400 mb-3 tracking-widest">Student Description</p>
                <p className="text-base text-indigo-900 font-medium leading-relaxed italic">"{selectedGrievance.description}"</p>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Mark Status</label>
                  <select 
                    value={statusInput}
                    onChange={(e) => setStatusInput(e.target.value as Status)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    <option value="">No change</option>
                    {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] uppercase font-black text-slate-400 tracking-widest">Official Remark</label>
                  <input 
                    type="text"
                    value={remarkInput}
                    onChange={(e) => setRemarkInput(e.target.value)}
                    placeholder="Brief summary of action taken..."
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>

              <button 
                onClick={handleUpdate}
                disabled={!statusInput && !remarkInput}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-[28px] hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 disabled:opacity-50"
              >
                Update & Notify Student
              </button>

              <div className="pt-8 border-t border-slate-100">
                <label className="text-[10px] uppercase font-black text-slate-400 block mb-6 tracking-widest">Redressal History</label>
                <div className="space-y-6">
                  {selectedGrievance.history.map((h, i) => (
                    <div key={i} className="flex gap-6 items-start">
                      <div className="w-1.5 h-10 bg-slate-100 rounded-full flex-shrink-0 relative">
                         <div className="absolute top-0 left-0 w-full h-1/2 bg-indigo-500 rounded-full"></div>
                      </div>
                      <div className="flex-1">
                        <div className="flex justify-between items-center mb-1">
                           <p className="font-bold text-slate-900 text-sm">{h.status}</p>
                           <p className="text-[10px] text-slate-400 font-bold">{new Date(h.timestamp).toLocaleTimeString()}</p>
                        </div>
                        {h.remark && <p className="text-xs text-slate-500 bg-slate-50 p-3 rounded-xl border border-slate-100">"{h.remark}"</p>}
                      </div>
                    </div>
                  )).reverse()}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagementConsole;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { getCurrentUser, logout } from '../store';
import { UserRole } from '../types';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [currentUser, setUser] = useState(getCurrentUser());

  useEffect(() => {
    const handleStorage = () => setUser(getCurrentUser());
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  if (!currentUser) return <>{children}</>;

  const navItems = [
    { path: '/', label: 'Submit Grievance', roles: [UserRole.STUDENT] },
    { path: '/track', label: 'My Grievances', roles: [UserRole.STUDENT] },
    // Fix: Removed non-existent UserRole.INCHARGE to resolve Property 'INCHARGE' does not exist error
    { path: '/dashboard', label: 'Management Console', roles: [UserRole.STAFF, UserRole.ADMIN] },
    { path: '/admin-view', label: 'Institution Analytics', roles: [UserRole.ADMIN] },
