import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import GrievanceChatbot from './components/GrievanceChatbot';
import GrievanceTracker from './components/GrievanceTracker';
import ManagementConsole from './components/ManagementConsole';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';
import { isAuthenticated, getCurrentUser } from './store';
import { UserRole } from './types';

const ProtectedRoute: React.FC<{ children: React.ReactNode; roles?: UserRole[] }> = ({ children, roles }) => {
  if (!isAuthenticated()) {
    return <Navigate to="/login" replace />;
  }

  const user = getCurrentUser();
  if (roles && user && !roles.includes(user.role)) {
    return <Navigate to={user.role === UserRole.STUDENT ? "/" : "/dashboard"} replace />;
  }

  return <>{children}</>;
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/login" element={<Login />} />

          <Route path="/" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceChatbot />
            </ProtectedRoute>
          } />

          <Route path="/track" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceTracker />
            </ProtectedRoute>
          } />

          <Route path="/dashboard" element={
            // Fix: Removed non-existent UserRole.INCHARGE to resolve Property 'INCHARGE' does not exist error
            <ProtectedRoute roles={[UserRole.STAFF, UserRole.ADMIN]}>
              <ManagementConsole />
            </ProtectedRoute>
          } />

          <Route path="/admin-view" element={
            <ProtectedRoute roles={[UserRole.ADMIN]}>
              <AdminDashboard />
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

// Removed module-level API_KEY to ensure process.env.API_KEY is accessed directly in functions

export const classifyGrievance = async (text: string) => {
  // Fix: Initialize GoogleGenAI right before making an API call using process.env.API_KEY directly
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Classify the following educational institution grievance: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          department: {
            type: Type.STRING,
            description: "One of: Hostel, Mess/Food, Academics, Administration, Hygiene, Electrical, Other",
          },
          severity: {
            type: Type.STRING,
            description: "One of: Low, Medium, High, Critical",
          },
          empatheticResponse: {
            type: Type.STRING,
            description: "A short, supportive acknowledging response for the user.",
          },
          summary: {
            type: Type.STRING,
            description: "A one-sentence professional summary of the issue.",
          }
        },
        required: ["department", "severity", "empatheticResponse", "summary"],
      },
    },
  });

  // Fix: Extract text directly from the response property
  return JSON.parse(response.text || '{}');
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  // Fix: Initialize GoogleGenAI right before making an API call using process.env.API_KEY directly
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));

  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are EduResolve Assistant, a helpful bot for an educational institution's grievance system. Be empathetic, objective, and professional. Ask for details if the grievance description is too short. If they are ready to submit, explain that their identity is safe.",
    },
  });

  // Fix: Extract text directly from the response property
  return response.text;
};

import React, { useState, useMemo } from 'react';
