                className="w-full bg-indigo-600 text-white font-black py-6 rounded-3xl hover:bg-indigo-700 active:scale-95 transition-all shadow-2xl shadow-indigo-200 disabled:opacity-50 text-xl"
              >
                Submit & Notify Complainant
              </button>

              <div className="pt-10 border-t border-slate-200">
                <label className="text-[11px] uppercase font-black text-slate-700 block mb-8 tracking-widest text-center">Audit Log</label>
                <div className="space-y-8">
                  {selectedGrievance.history.map((h, i) => (
                    <div key={i} className="flex gap-8 items-start relative">
                      <div className="w-1.5 h-full bg-slate-200 rounded-full absolute left-4 top-0 -z-10"></div>
                      <div className="w-10 h-10 bg-white border-4 border-indigo-600 rounded-2xl flex-shrink-0 flex items-center justify-center font-black text-xs text-indigo-600 shadow-sm">
                        {selectedGrievance.history.length - i}
                      </div>
                      <div className="flex-1 bg-slate-50 p-6 rounded-3xl border border-slate-200 shadow-sm">
                        <div className="flex justify-between items-center mb-3">
                           <p className="font-black text-slate-900 uppercase tracking-widest text-xs">{h.status}</p>
                           <p className="text-[10px] text-slate-600 font-black">{new Date(h.timestamp).toLocaleString()}</p>
                        </div>
                        {h.remark && <p className="text-sm text-slate-900 font-medium italic border-l-4 border-indigo-400 pl-4 py-1">"{h.remark}"</p>}
                      </div>
                    </div>
                  )).reverse()}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

