export const getResponsibleStaffId = (dept: Department): string => {
  const staff = MOCK_USERS.find(u => u.department === dept);
  return staff ? staff.id : 'ADM-ADMIN';
};

export const isAuthenticated = (): boolean => localStorage.getItem(AUTH_KEY) === 'true';

export const getCurrentUser = (): User | null => {
  if (!isAuthenticated()) return null;
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : null;
};

export const login = (userId: string, password: string): boolean => {
  const user = MOCK_USERS.find(u => u.id === userId && u.password === password);
  if (user) {
    const { password: _, ...userData } = user;
    localStorage.setItem(USER_KEY, JSON.stringify(userData));
    localStorage.setItem(AUTH_KEY, 'true');
    window.dispatchEvent(new Event('storage'));
    return true;
  }
  return false;
};

export const logout = () => {
  localStorage.removeItem(USER_KEY);
  localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('storage'));
};

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(GRIEVANCE_KEY);
  return data ? JSON.parse(data) : [];
};

export const getMyGrievances = (userId: string): Grievance[] => {
  return getGrievances().filter(g => g.studentId === userId);
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();
  localStorage.setItem(GRIEVANCE_KEY, JSON.stringify([...current, grievance]));
};

export const updateGrievance = (updatedG: Grievance) => {
  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    const oldStatus = current[index].status;
    if (oldStatus !== updatedG.status) {
      updatedG.notificationsSent.push({
        type: 'email',
        timestamp: Date.now(),
        message: `Official Notice: Grievance #${updatedG.id} updated to ${updatedG.status.toUpperCase()}.`
      });
    }
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

export const findGrievanceById = (id: string) => getGrievances().find(g => g.id === id);

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { classifyGrievance } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'DESCRIBING' | 'CONFIRMING_DEPT' | 'VERIFYING_CONTEXT' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('DESCRIBING');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}! I'm your EduResolve AI. Please describe your concern in detail.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [pendingGrievance, setPendingGrievance] = useState<Partial<Grievance>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    if (state === 'DESCRIBING') {
      setIsTyping(true);
      try {
        const classification = await classifyGrievance(userMessage);
        const dept = classification.department as Department;

        setPendingGrievance({
          description: userMessage,
          department: dept,
          severity: classification.severity as Severity,
        });

        addBotMessage(`I've identified this as a **${dept}** issue. Is this correct? If so, I'll transfer it to the appropriate department for resolution.`);
        setState('CONFIRMING_DEPT');
      } catch (err) {
        addBotMessage("I couldn't quite categorize that. Could you provide a bit more detail?");
      } finally {
        setIsTyping(false);
      }
    } 

    else if (state === 'CONFIRMING_DEPT') {
      if (userMessage.toLowerCase().includes('yes') || userMessage.toLowerCase().includes('ok')) {
        // Step 2: Context Verification based on Login
        const dept = pendingGrievance.department;
        if (dept === Department.HOSTEL) {
          addBotMessage(`I see you are assigned to **${currentUser?.assignedHostel || 'the hostel'}**. Does this issue pertain to your specific block/room or a common area?`);
          setState('VERIFYING_CONTEXT');
        } else if (dept === Department.ACADEMICS) {
          addBotMessage(`Noted. Since you are in the **${currentUser?.studentDept}** department, should I route this specifically to your departmental dean?`);
          setState('VERIFYING_CONTEXT');
        } else {
          finalizeGrievance();
        }
      } else {
        addBotMessage("I apologize for the misunderstanding. Please describe the issue again so I can re-classify it.");
        setState('DESCRIBING');
      }
    } 

    else if (state === 'VERIFYING_CONTEXT') {
      finalizeGrievance(userMessage);
    }
  };

  const finalizeGrievance = (additionalContext?: string) => {
    const grievanceId = 'GRV-' + Math.random().toString(36).substring(2, 8).toUpperCase();
    const now = Date.now();
    const dept = pendingGrievance.department as Department;
    const assignedStaffId = getResponsibleStaffId(dept);
    const staffName = MOCK_USERS.find(u => u.id === assignedStaffId)?.name || 'Department Desk';

    const fullDescription = additionalContext 
      ? `${pendingGrievance.description} | Verification Context: ${additionalContext}`
      : pendingGrievance.description || "";

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: fullDescription,
      department: dept,
      severity: pendingGrievance.severity as Severity,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: assignedStaffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: currentUser?.id || 'ANON' }],
      remarks: [],
      notificationsSent: [{
        type: 'email',
        timestamp: now,
        message: `Grievance #${grievanceId} successfully routed to ${staffName}.`
      }]
    };

    saveGrievance(newGrievance);
    addBotMessage(`Excellent. I've officially transferred your grievance to **${staffName}**. You can track progress using Ref ID: **${grievanceId}**.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping || state === 'DONE') return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-3xl mx-auto flex flex-col h-[calc(100vh-14rem)]">
      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-8 bg-indigo-700 flex items-center justify-between text-white">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center border border-white/20 shadow-inner">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-xl font-black tracking-tight">EduResolve AI</h2>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
                <p className="text-[10px] font-black uppercase tracking-widest opacity-80">Connected as {currentUser?.id}</p>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3 bg-white/10 px-5 py-2.5 rounded-2xl border border-white/10">
            <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Anonymous</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-12 h-6 rounded-full transition-all relative ${isAnonymous ? 'bg-emerald-500' : 'bg-slate-400'}`}
            >
              <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow-md ${isAnonymous ? 'left-7' : 'left-1'}`}></div>
            </button>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-10 space-y-6 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-3xl rounded-tr-none' : 'bg-white text-slate-900 border-2 border-slate-100 rounded-3xl rounded-tl-none'} p-6 shadow-sm`}>
                <p className="text-sm font-bold leading-relaxed whitespace-pre-wrap">{msg.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start items-center gap-2">
              <div className="flex gap-1.5 bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.1s]"></span>
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              </div>
            </div>
          )}
          <div ref={scrollRef}></div>
        </div>

        {/* Input Area */}
        <div className="p-6 bg-white border-t-4 border-slate-50">
          <form onSubmit={handleSubmit} className="flex gap-4">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Grievance submitted." : "Type your message..."}
