import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { classifyGrievance, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'CHATTING' | 'CONFIRMING_DEPT' | 'VERIFYING_CONTEXT' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('CHATTING');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hey ${currentUser?.name}! I'm here to help. Whether you have a question or need to report a problem, just let me know.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [pendingGrievance, setPendingGrievance] = useState<Partial<Grievance>>({});

  const scrollRef = useRef<HTMLDivElement>(null);
  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'CHATTING') {
      // Use Gemini to determine if this is a complaint or just chat
      try {
        const botResponse = await getBotResponse(messages, userMessage);

        // Simple heuristic: if the bot thinks a complaint is being made, or we see keywords, we classify
        const isLikelyComplaint = userMessage.length > 20 || 
                                 /problem|issue|complain|broken|bad|not working|error|fault|grievance/i.test(userMessage);

        if (isLikelyComplaint) {
          const classification = await classifyGrievance(userMessage);
          const dept = classification.department as Department;

          setPendingGrievance({
            description: userMessage,
            department: dept,
            severity: classification.severity as Severity,
          });

          addBotMessage(`${classification.empatheticResponse}\n\nI've identified this as a **${dept}** issue. Is this your problem? I'll transfer it to the appropriate department if you say OK.`);
          setState('CONFIRMING_DEPT');
        } else {
          addBotMessage(botResponse || "I'm listening. Tell me more about what's on your mind.");
        }
      } catch (err) {
        addBotMessage("I'm having trouble processing that. Could you describe your concern more clearly?");
      } finally {
        setIsTyping(false);
      }
    } 

    else if (state === 'CONFIRMING_DEPT') {
      setIsTyping(false);
      const lowerMsg = userMessage.toLowerCase();
      if (lowerMsg.includes('ok') || lowerMsg.includes('yes') || lowerMsg.includes('sure') || lowerMsg.includes('correct')) {
        const dept = pendingGrievance.department;

        // Contextual Verification
        if (dept === Department.HOSTEL) {
          addBotMessage(`I see from your profile that you reside in **${currentUser?.assignedHostel}**. Are you reporting this for that specific block/room?`);
          setState('VERIFYING_CONTEXT');
        } else if (dept === Department.ACADEMICS) {
          addBotMessage(`Since you are enrolled in **${currentUser?.studentDept}**, should I route this to your department head specifically?`);
          setState('VERIFYING_CONTEXT');
        } else {
          finalizeGrievance();
        }
      } else {
        addBotMessage("My apologies. Let's start over. What is the specific problem you're facing?");
        setState('CHATTING');
      }
    } 

    else if (state === 'VERIFYING_CONTEXT') {
      setIsTyping(false);
      finalizeGrievance(userMessage);
    }
  };

  const finalizeGrievance = (verificationResponse?: string) => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = pendingGrievance.department as Department;
    const assignedStaffId = getResponsibleStaffId(dept);
    const staffMember = MOCK_USERS.find(u => u.id === assignedStaffId);

    const fullDescription = verificationResponse 
      ? `${pendingGrievance.description} (User confirmed context: ${verificationResponse})`
      : pendingGrievance.description || "";

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: fullDescription,
      department: dept,
      severity: pendingGrievance.severity as Severity,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANONYMOUS',
      assignedToId: assignedStaffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: currentUser?.id || 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'email',
        timestamp: now,
        message: `Grievance registered. Transferred to ${staffMember?.name} (${dept} Dept).`
      }]
    };

    saveGrievance(newGrievance);
    addBotMessage(`Understood. I have officially transferred your case to **${staffMember?.name}**. \n\nTrack your resolution using Reference ID: **${grievanceId}**.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping || state === 'DONE') return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-3xl mx-auto flex flex-col h-[calc(100vh-14rem)]">
      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-8 bg-slate-900 flex items-center justify-between text-white">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-2xl font-black tracking-tight">EduResolve Bot</h2>
              <div className="flex items-center gap-2">
                <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse"></span>
                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Secure Live Connection</p>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-end gap-2">
            <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-xl border border-white/10">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Anonymity</span>
              <button 
                onClick={() => setIsAnonymous(!isAnonymous)}
                className={`w-12 h-6 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-700'}`}
              >
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow-md ${isAnonymous ? 'left-7' : 'left-1'}`}></div>
              </button>
            </div>
            {isAnonymous ? (
              <span className="text-[9px] font-bold text-emerald-400 uppercase tracking-widest">Identity Protected</span>
            ) : (
              <span className="text-[9px] font-bold text-orange-400 uppercase tracking-widest">Sharing ID: {currentUser?.id}</span>
            )}
          </div>
        </div>

        {/* Chat Bubbles */}
        <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-slate-50/30">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
              <div className={`max-w-[85%] ${
                msg.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-[28px] rounded-tr-none shadow-xl' 
                  : 'bg-white text-slate-900 border-2 border-slate-100 rounded-[28px] rounded-tl-none shadow-sm'
              } p-6`}>
                <p className="text-[15px] font-bold leading-relaxed whitespace-pre-wrap">{msg.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-white border-2 border-slate-100 p-5 rounded-2xl flex gap-1.5">
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef}></div>
        </div>

        {/* User Input */}
        <div className="p-8 bg-white border-t-4 border-slate-50">
          <form onSubmit={handleSubmit} className="flex gap-4">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Grievance has been transferred." : "Message EduResolve..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-2 border-slate-200 rounded-[30px] px-8 py-5 text-slate-900 font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all placeholder:text-slate-400"
            />
            <button
              type="submit"
              disabled={!input.trim() || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-16 h-16 rounded-full flex items-center justify-center hover:bg-slate-900 active:scale-90 transition-all shadow-xl shadow-indigo-100 disabled:opacity-20"
            >
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
          {state === 'DONE' && (
            <button 
              onClick={() => { setMessages([{ role: 'assistant', content: "Back in chat mode. How can I assist you now?" }]); setState('CHATTING'); }}
              className="mt-6 w-full py-3 bg-slate-100 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 transition-colors"
            >
              Start New Conversation
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

