import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

export const classifyGrievance = async (text: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze this educational institution complaint: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          department: {
            type: Type.STRING,
            description: "One of: Hostel, Mess/Food, Academics, Administration, Hygiene, Electrical, Other",
          },
          severity: {
            type: Type.STRING,
            description: "One of: Low, Medium, High, Critical",
          },
          empatheticResponse: {
            type: Type.STRING,
            description: "A warm, professional acknowledgment of the user's frustration.",
          },
          summary: {
            type: Type.STRING,
            description: "A clear, concise summary of the core issue reported by the student.",
          },
          reasoning: {
            type: Type.STRING,
            description: "Briefly explain why this belongs to the chosen department.",
          }
        },
        required: ["department", "severity", "empatheticResponse", "summary", "reasoning"],
      },
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));

  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are the EduResolve Interactive Assistant. You must act like a real person—polite, conversational, and helpful. Respond to greetings normally. If the user mentions a problem, encourage them to describe it in detail. DO NOT use technical jargon. If they are talking about a specific issue, ask follow-up questions to understand the 'who, what, where'. Be concise but friendly.",
    },
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { classifyGrievance, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'GREETING' | 'DISCUSSING_ISSUE' | 'CONFIRMING_SUMMARY' | 'VERIFYING_IDENTITY' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('GREETING');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hi ${currentUser?.name}! I'm your institutional assistant. How are you doing today? Is there anything on your mind?` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [processStatus, setProcessStatus] = useState<string>('Waiting for interaction...');
  const [pendingGrievance, setPendingGrievance] = useState<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'GREETING' || state === 'DISCUSSING_ISSUE') {
      const lowerInput = userMessage.toLowerCase();
      // Simple detection if user is actually reporting a problem
      const isReporting = /problem|issue|complain|broken|bad|not working|error|fault|grievance|fail|mess|dirty|academics/i.test(lowerInput) && userMessage.length > 15;

      if (isReporting) {
        setProcessStatus('Analyzing your complaint...');
        try {
          const result = await classifyGrievance(userMessage);
          setPendingGrievance(result);

          addBotMessage(`${result.empatheticResponse}\n\nI've summarized your issue: **"${result.summary}"**\n\nI've identified this as a **${result.department}** matter because ${result.reasoning}. \n\nIs this your problem? If you say "OK", I'll transfer it to the appropriate department for resolution.`);
          setState('CONFIRMING_SUMMARY');
          setProcessStatus('Awaiting transfer consent...');
        } catch (err) {
          addBotMessage("I'm sorry, I had a bit of trouble understanding that. Could you tell me a bit more about the issue?");
          setState('DISCUSSING_ISSUE');
        }
      } else {
        // Just chatting
        setProcessStatus('Engaged in conversation...');
        const botResponse = await getBotResponse(messages, userMessage);
        addBotMessage(botResponse || "I see. Tell me more, I'm here to listen.");
        setState('DISCUSSING_ISSUE');
      }
    } 

    else if (state === 'CONFIRMING_SUMMARY') {
      const lower = userMessage.toLowerCase();
      if (lower.includes('ok') || lower.includes('yes') || lower.includes('sure') || lower.includes('transfer')) {
        setProcessStatus('Verifying institutional context...');
        const dept = pendingGrievance.department;

        // Ask context-specific verification based on login data
        if (dept === Department.HOSTEL) {
          addBotMessage(`Perfect. I see from your records that you're staying in **${currentUser?.assignedHostel}**. Is this complaint specifically about that residence or somewhere else?`);
          setState('VERIFYING_IDENTITY');
        } else if (dept === Department.ACADEMICS) {
          addBotMessage(`Noted. Since you are in the **${currentUser?.studentDept}** department, should I notify your specific dean about this?`);
          setState('VERIFYING_IDENTITY');
        } else {
          finalizeGrievance("Context automatically verified via student profile.");
        }
      } else {
        addBotMessage("I see. Let's try again. Can you describe the problem in a different way so I can get it right?");
        setState('DISCUSSING_ISSUE');
        setProcessStatus('Restarting understanding process...');
      }
    } 

    else if (state === 'VERIFYING_IDENTITY') {
      setProcessStatus('Finalizing submission...');
      finalizeGrievance(userMessage);
    }

    setIsTyping(false);
  };

  const finalizeGrievance = (contextNotes: string) => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = pendingGrievance.department as Department;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const fullDesc = `${pendingGrievance.description}\n\n[Verification Detail]: ${contextNotes}`;

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: fullDesc,
      department: dept,
      severity: pendingGrievance.severity as Severity,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'in-app',
        timestamp: now,
        message: `Case successfully transferred to ${staff?.name} (${dept} Dept).`
      }]
    };

    saveGrievance(newGrievance);
    addBotMessage(`Done! I've completed the transfer. Your case is now with **${staff?.name}**. \n\nYou can track it anytime using Reference ID: **${grievanceId}**.\n\nIs there anything else I can do for you?`);
    setState('DONE');
    setProcessStatus('Grievance Logged Successfully.');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping || state === 'DONE') return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] gap-6">
      {/* Bot Thinking/Process Indicator */}
      <div className="bg-white border-b-4 border-indigo-600 rounded-[28px] px-8 py-4 shadow-xl flex items-center justify-between">
         <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isTyping ? 'bg-orange-500 animate-pulse' : 'bg-emerald-500'}`}></div>
            <p className="text-[11px] font-black text-slate-900 uppercase tracking-widest">{processStatus}</p>
         </div>
         <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {state.replace('_', ' ')}
         </div>
      </div>

      <div className="bg-white rounded-[48px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-10 bg-slate-950 flex items-center justify-between text-white border-b-8 border-indigo-600/20">
          <div className="flex items-center gap-6">
            <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center shadow-2xl rotate-3">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-3xl font-black tracking-tighter">EduResolve AI</h2>
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Human-AI Hybrid Redressal</p>
            </div>
          </div>

          <div className="flex flex-col items-end gap-3">
            <div className="flex items-center gap-4 bg-white/5 px-6 py-3 rounded-2xl border border-white/10">
              <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Incognito Mode</span>
              <button 
                onClick={() => setIsAnonymous(!isAnonymous)}
                className={`w-14 h-7 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.5)]' : 'bg-slate-700'}`}
              >
                <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-all shadow-lg ${isAnonymous ? 'left-8' : 'left-1'}`}></div>
              </button>
            </div>
            <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">
               {isAnonymous ? 'Identity Hidden from Staff' : `Reporting as: ${currentUser?.id}`}
            </p>
          </div>
        </div>

        {/* Chat Stream */}
        <div className="flex-1 overflow-y-auto p-12 space-y-10 bg-slate-50/40">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] ${
                msg.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-[32px] rounded-tr-none shadow-2xl' 
                  : 'bg-white text-slate-900 border-4 border-slate-50 rounded-[32px] rounded-tl-none shadow-md'
              } p-8 relative`}>
                <p className="text-lg font-bold leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                {msg.role === 'assistant' && i === 0 && (
                   <span className="absolute -top-4 -left-2 bg-indigo-600 text-white text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest">Bot</span>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-white border-4 border-slate-50 p-6 rounded-3xl flex gap-2">
                <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce"></div>
                <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef}></div>
        </div>

        {/* Input Dock */}
        <div className="p-10 bg-white border-t-8 border-slate-50">
          <form onSubmit={handleSubmit} className="flex gap-6">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Session complete." : "Type your message here..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-4 border-transparent rounded-[35px] px-10 py-6 text-slate-900 font-bold text-lg focus:border-indigo-600 focus:bg-white outline-none transition-all placeholder:text-slate-400"
            />
            <button
              type="submit"
              disabled={!input.trim() || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-20 h-20 rounded-[30px] flex items-center justify-center hover:bg-slate-900 active:scale-90 transition-all shadow-2xl shadow-indigo-100 disabled:opacity-20"
            >
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
          {state === 'DONE' && (
            <div className="mt-8 flex gap-4">
              <button 
                onClick={() => { 
                   setMessages([{ role: 'assistant', content: "Okay, I'm ready for another chat. What's happening?" }]); 
                   setState('GREETING'); 
                   setProcessStatus('Fresh session started.');
                }}
                className="flex-1 py-5 bg-indigo-50 text-indigo-700 rounded-3xl font-black text-xs uppercase tracking-[0.2em] hover:bg-indigo-100 transition-all"
              >
                New Conversation
              </button>
              <button 
                onClick={() => window.location.hash = '/track'}
                className="flex-1 py-5 bg-slate-900 text-white rounded-3xl font-black text-xs uppercase tracking-[0.2em] hover:bg-black transition-all"
              >
                Track History
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

