import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { analyzeGrievanceState, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'CHATTING' | 'GATHERING_DETAILS' | 'REQUESTING_PROOF' | 'CONFIRMING' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('CHATTING');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hey ${currentUser?.name}! How can I help you today? If something is bothering you, feel free to share it here.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [pendingGrievance, setPendingGrievance] = useState<any>(null);
  const [currentAttachments, setCurrentAttachments] = useState<Attachment[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string, attachments?: Attachment[]) => {
    setMessages(prev => [...prev, { role: 'assistant', content, attachments }]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = ev.target?.result as string;
        setCurrentAttachments(prev => [...prev, { name: file.name, type: file.type, data: base64 }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'CHATTING' || state === 'GATHERING_DETAILS') {
      const isInitialComplaint = userMessage.length > 10 && /problem|issue|complain|broken|bad|fail|error|incident/i.test(userMessage);

      if (isInitialComplaint || state === 'GATHERING_DETAILS') {
        try {
          const analysis = await analyzeGrievanceState(userMessage, messages);
          setPendingGrievance((prev: any) => ({
            ...analysis,
            description: prev?.description ? `${prev.description}\n\n[Update]: ${userMessage}` : userMessage
          }));

          if (!analysis.isDetailedEnough) {
            addBotMessage(analysis.followUpQuestion || "Could you provide a few more details so I can help you better?");
            setState('GATHERING_DETAILS');
          } else {
            if (analysis.isSensitive && state !== 'REQUESTING_PROOF') {
              addBotMessage(`This sounds quite serious. To ensure a thorough investigation, do you have any photos, audio recordings, or documents you'd like to upload as evidence? You can use the attachment icon below.`);
              setState('REQUESTING_PROOF');
            } else {
              addBotMessage(`I've gathered the details. \n\n**Summary:** ${analysis.summary}\n\nThis will be routed to the **${analysis.department}** department. Is this correct? If so, say "OK" and I will transfer it.`);
              setState('CONFIRMING');
            }
          }
        } catch (err) {
          addBotMessage("I'm having a bit of trouble processing that. Can we try again?");
        }
      } else {
        const botResponse = await getBotResponse(messages, userMessage);
        addBotMessage(botResponse || "I see. Tell me more.");
      }
    } 

    else if (state === 'REQUESTING_PROOF') {
      // User typed something after being asked for proof
      addBotMessage(`Got it. Here is the summary of what we have: \n\n**Summary:** ${pendingGrievance.summary}\n\nShall I proceed with the transfer to **${pendingGrievance.department}**?`);
      setState('CONFIRMING');
    }

    else if (state === 'CONFIRMING') {
      if (/ok|yes|sure|go ahead/i.test(userMessage)) {
        finalizeGrievance();
      } else {
        addBotMessage("No problem. Let's adjust. What did I get wrong?");
        setState('GATHERING_DETAILS');
      }
    }

    setIsTyping(false);
  };

  const finalizeGrievance = () => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = pendingGrievance.department as Department;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: pendingGrievance.description,
      department: dept,
      severity: pendingGrievance.severity as Severity,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANONYMOUS',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'in-app',
        timestamp: now,
        message: `Case registered and assigned to ${staff?.name}.`
      }],
      attachments: currentAttachments
    };

    saveGrievance(newGrievance);
    addBotMessage(`Excellent. I have officially transferred your grievance to **${staff?.name}**. \n\nReference ID: **${grievanceId}**. \n\nYou can track the progress in the 'My Grievances' section.`);
    setState('DONE');
    setCurrentAttachments([]);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && currentAttachments.length === 0) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg, attachments: currentAttachments }]);
    setInput('');
    setCurrentAttachments([]);
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)]">
      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-8 bg-slate-900 flex items-center justify-between text-white">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-xl font-black">EduResolve AI</h2>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Active Investigation</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Anonymous</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-12 h-6 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-700'}`}
            >
              <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isAnonymous ? 'left-7' : 'left-1'}`}></div>
            </button>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] ${
                msg.role === 'user' ? 'bg-slate-900 text-white rounded-3xl rounded-tr-none' : 'bg-white text-slate-900 border-2 border-slate-100 rounded-3xl rounded-tl-none shadow-sm'
              } p-6`}>
                <p className="text-[15px] font-bold leading-relaxed">{msg.content}</p>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-4 flex flex-wrap gap-2">
                    {msg.attachments.map((at, idx) => (
                      <div key={idx} className="bg-slate-800/50 p-2 rounded-xl border border-white/10 flex items-center gap-2 max-w-xs">
                         {at.type.startsWith('image/') ? (
                           <img src={at.data} className="w-10 h-10 object-cover rounded-lg" alt="preview" />
                         ) : (
                           <div className="w-10 h-10 bg-indigo-500 rounded-lg flex items-center justify-center text-[10px] font-black uppercase">DOC</div>
                         )}
                         <span className="text-[10px] font-medium truncate">{at.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && <div className="p-4 bg-white border-2 border-slate-100 rounded-2xl w-max animate-pulse font-black text-[10px] uppercase text-indigo-600 tracking-widest">Bot is thinking...</div>}
          <div ref={scrollRef}></div>
        </div>

        {/* Interaction Dock */}
        <div className="p-8 bg-white border-t-4 border-slate-50">
          {currentAttachments.length > 0 && (
            <div className="mb-4 flex flex-wrap gap-3">
               {currentAttachments.map((at, i) => (
                 <div key={i} className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-full text-[10px] font-black flex items-center gap-2 border border-indigo-100">
                    <span className="truncate max-w-[100px]">{at.name}</span>
                    <button onClick={() => setCurrentAttachments(prev => prev.filter((_, idx) => idx !== i))} className="text-red-500">✕</button>
                 </div>
               ))}
            </div>
          )}
          <form onSubmit={handleSubmit} className="flex gap-4">
            <button 
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-slate-200 transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple />

            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Session concluded." : "Provide more details or say OK..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-2 border-slate-200 rounded-2xl px-6 py-4 text-slate-900 font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all"
            />
            <button
              type="submit"
              disabled={(!input.trim() && currentAttachments.length === 0) || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-14 h-14 rounded-2xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-xl disabled:opacity-30"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

