              <span className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest ${COLORS.status[g.status]}`}>
                {g.status}
              </span>
              <span className="text-[10px] font-black text-slate-400">#{g.id}</span>
            </div>

            <p className="text-slate-900 text-lg font-bold mb-8 italic">"{g.description.split('\n\n')[0]}..."</p>

            {g.attachments && g.attachments.length > 0 && (
               <div className="flex items-center gap-2 mb-8 bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
                     <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4 3a2 2 0 100 4h12a2 2 0 100-4H4z" /><path fillRule="evenodd" d="M3 8h14v7a2 2 0 01-2 2H5a2 2 0 01-2-2V8zm5 3a1 1 0 011-1h2a1 1 0 110 2H9a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                  </div>
                  <span className="text-[10px] font-black text-indigo-700 uppercase tracking-widest">{g.attachments.length} Evidence Files Attached</span>
               </div>
            )}

            <div className="flex items-center justify-between pt-8 border-t-2 border-slate-50">
              <span className={`text-[10px] font-black px-5 py-2.5 rounded-full uppercase border shadow-inner ${COLORS.severity[g.severity]}`}>
                {g.severity} Priority
              </span>
              <button 
                onClick={() => setSelectedGrievance(g)}
                className="bg-slate-900 text-white text-[10px] px-8 py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-indigo-600 transition-all"
              >
                Inspect Case
              </button>
            </div>
          </div>
        ))}
      </div>

      {selectedGrievance && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[50px] shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-12 border-b-4 border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h4 className="font-black text-slate-900 text-4xl">Ticket #{selectedGrievance.id}</h4>
              <button onClick={() => setSelectedGrievance(null)} className="w-14 h-14 bg-white border-4 border-slate-100 rounded-2xl flex items-center justify-center hover:bg-red-50 hover:text-red-500 transition-all">
                ✕
              </button>
            </div>

            <div className="p-12 space-y-10 overflow-y-auto">
              <div className="bg-slate-900 p-10 rounded-[40px] text-white">
                <p className="text-[10px] uppercase font-black text-slate-500 mb-6 tracking-widest">Full Statement</p>
                <p className="text-xl font-medium leading-relaxed italic">"{selectedGrievance.description}"</p>
              </div>

              {selectedGrievance.attachments && selectedGrievance.attachments.length > 0 && (
                <div>
                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6 ml-2">Evidence & Proof</p>
                   <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
