                  >
                    <option value="">Choose Transition...</option>
                    {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="space-y-4">
                  <label className="text-[11px] font-black text-slate-500 uppercase ml-2 tracking-widest">Add Remark</label>
                  <input 
                    type="text"
                    value={remarkInput}
                    onChange={(e) => setRemarkInput(e.target.value)}
                    placeholder="Briefly state action..."
                    className="w-full bg-slate-50 border-4 border-slate-100 rounded-3xl px-8 py-6 text-slate-900 font-bold focus:border-indigo-600 outline-none transition-all"
                  />
