              </div>

              <button 
                onClick={handleUpdate}
                disabled={!statusInput && !remarkInput}
                className="w-full bg-indigo-600 text-white font-black py-10 rounded-[35px] hover:bg-slate-900 transition-all shadow-2xl disabled:opacity-20 text-2xl tracking-tight"
              >
                Finalize Resolution Update
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

