import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { analyzeGrievanceState, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'CHATTING' | 'GATHERING_DETAILS' | 'REQUESTING_PROOF' | 'CONFIRMING' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('CHATTING');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hey ${currentUser?.name}! How can I help you today? If something is bothering you, feel free to share it here.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [pendingGrievance, setPendingGrievance] = useState<any>(null);
  const [currentAttachments, setCurrentAttachments] = useState<Attachment[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string, attachments?: Attachment[]) => {
    setMessages(prev => [...prev, { role: 'assistant', content, attachments }]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = ev.target?.result as string;
        setCurrentAttachments(prev => [...prev, { name: file.name, type: file.type, data: base64 }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'CHATTING' || state === 'GATHERING_DETAILS') {
      const isInitialComplaint = userMessage.length > 10 && /problem|issue|complain|broken|bad|fail|error|incident/i.test(userMessage);

      if (isInitialComplaint || state === 'GATHERING_DETAILS') {
        try {
          const analysis = await analyzeGrievanceState(userMessage, messages);
          setPendingGrievance((prev: any) => ({
            ...analysis,
            description: prev?.description ? `${prev.description}\n\n[Update]: ${userMessage}` : userMessage
          }));

          if (!analysis.isDetailedEnough) {
            addBotMessage(analysis.followUpQuestion || "Could you provide a few more details so I can help you better?");
            setState('GATHERING_DETAILS');
          } else {
            // Fix: Removed redundant 'state !== REQUESTING_PROOF' check to resolve TypeScript comparison error.
            // Since we are inside a block where state is either 'CHATTING' or 'GATHERING_DETAILS', this is always true.
            if (analysis.isSensitive) {
              addBotMessage(`This sounds quite serious. To ensure a thorough investigation, do you have any photos, audio recordings, or documents you'd like to upload as evidence? You can use the attachment icon below.`);
              setState('REQUESTING_PROOF');
            } else {
              addBotMessage(`I've gathered the details. \n\n**Summary:** ${analysis.summary}\n\nThis will be routed to the **${analysis.department}** department. Is this correct? If so, say "OK" and I will transfer it.`);
              setState('CONFIRMING');
            }
          }
        } catch (err) {
          addBotMessage("I'm having a bit of trouble processing that. Can we try again?");
        }
      } else {
        const botResponse = await getBotResponse(messages, userMessage);
        addBotMessage(botResponse || "I see. Tell me more.");
      }
    } 

    else if (state === 'REQUESTING_PROOF') {
      // User typed something after being asked for proof
      addBotMessage(`Got it. Here is the summary of what we have: \n\n**Summary:** ${pendingGrievance.summary}\n\nShall I proceed with the transfer to **${pendingGrievance.department}**?`);
      setState('CONFIRMING');
    }

    else if (state === 'CONFIRMING') {
      if (/ok|yes|sure|go ahead/i.test(userMessage)) {
        finalizeGrievance();
      } else {
        addBotMessage("No problem. Let's adjust. What did I get wrong?");
        setState('GATHERING_DETAILS');
      }
    }

    setIsTyping(false);
  };

  const finalizeGrievance = () => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = pendingGrievance.department as Department;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: pendingGrievance.description,
      department: dept,
      severity: pendingGrievance.severity as Severity,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANONYMOUS',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'in-app',
        timestamp: now,
        message: `Case registered and assigned to ${staff?.name}.`
      }],
      attachments: currentAttachments
    };

    saveGrievance(newGrievance);
    addBotMessage(`Excellent. I have officially transferred your grievance to **${staff?.name}**. \n\nReference ID: **${grievanceId}**. \n\nYou can track the progress in the 'My Grievances' section.`);
    setState('DONE');
    setCurrentAttachments([]);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && currentAttachments.length === 0) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg, attachments: currentAttachments }]);
    setInput('');
    setCurrentAttachments([]);
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)]">
      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-8 bg-slate-900 flex items-center justify-between text-white">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-xl font-black">EduResolve AI</h2>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Active Investigation</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Anonymous</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-12 h-6 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-700'}`}
            >
              <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isAnonymous ? 'left-7' : 'left-1'}`}></div>
            </button>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] ${
                msg.role === 'user' ? 'bg-slate-900 text-white rounded-3xl rounded-tr-none' : 'bg-white text-slate-900 border-2 border-slate-100 rounded-3xl rounded-tl-none shadow-sm'
              } p-6`}>
                <p className="text-[15px] font-bold leading-relaxed">{msg.content}</p>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-4 flex flex-wrap gap-2">
                    {msg.attachments.map((at, idx) => (
                      <div key={idx} className="bg-slate-800/50 p-2 rounded-xl border border-white/10 flex items-center gap-2 max-w-xs">
                         {at.type.startsWith('image/') ? (
                           <img src={at.data} className="w-10 h-10 object-cover rounded-lg" alt="preview" />
                         ) : (
                           <div className="w-10 h-10 bg-indigo-500 rounded-lg flex items-center justify-center text-[10px] font-black uppercase">DOC</div>
                         )}
                         <span className="text-[10px] font-medium truncate">{at.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && <div className="p-4 bg-white border-2 border-slate-100 rounded-2xl w-max animate-pulse font-black text-[10px] uppercase text-indigo-600 tracking-widest">Bot is thinking...</div>}
          <div ref={scrollRef}></div>
        </div>

        {/* Interaction Dock */}
        <div className="p-8 bg-white border-t-4 border-slate-50">
          {currentAttachments.length > 0 && (
            <div className="mb-4 flex flex-wrap gap-3">
               {currentAttachments.map((at, i) => (
                 <div key={i} className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-full text-[10px] font-black flex items-center gap-2 border border-indigo-100">
                    <span className="truncate max-w-[100px]">{at.name}</span>
                    <button onClick={() => setCurrentAttachments(prev => prev.filter((_, idx) => idx !== i))} className="text-red-500">✕</button>
                 </div>
               ))}
            </div>
          )}
          <form onSubmit={handleSubmit} className="flex gap-4">
            <button 
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-slate-200 transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple />

            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Session concluded." : "Provide more details or say OK..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-2 border-slate-200 rounded-2xl px-6 py-4 text-slate-900 font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all"
            />
            <button
              type="submit"
              disabled={(!input.trim() && currentAttachments.length === 0) || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-14 h-14 rounded-2xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-xl disabled:opacity-30"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

export const analyzeGrievanceState = async (text: string, history: { role: string; content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Conversation History: ${JSON.stringify(history)}\nLatest User Input: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: {
            type: Type.BOOLEAN,
            description: "True if what happened, where, and when are all clear.",
          },
          missingPoints: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of specific details still needed (e.g., 'Exact room number', 'Time of incident').",
          },
          followUpQuestion: {
            type: Type.STRING,
            description: "A VERY SHORT, direct question (max 15 words) asking for the missing info.",
          },
          isSensitive: {
            type: Type.BOOLEAN,
            description: "True if this is high-severity or needs evidence.",
          },
          department: {
            type: Type.STRING,
            description: "Hostel, Mess/Food, Academics, Administration, Hygiene, Electrical, or Other.",
          },
          severity: {
            type: Type.STRING,
            description: "Low, Medium, High, or Critical.",
          },
          summary: {
            type: Type.STRING,
            description: "One-sentence summary of the grievance so far.",
          }
        },
        required: ["isDetailedEnough", "missingPoints", "followUpQuestion", "isSensitive", "department", "severity", "summary"],
      },
      systemInstruction: "You are a concise grievance investigator. NEVER write long paragraphs. Your job is to extract: 1. Nature of issue, 2. Specific Location, 3. Context/Timing. If any are missing, ask for them one by one in a very brief, helpful tone. Do not repeat yourself.",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));
  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are EduResolve AI. Be brief. Greet the user with 1-2 short sentences. If they mention a problem, transition immediately to asking for details. NO NOVELS.",
    },
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { ICONS } from '../constants';
import { analyzeGrievanceState, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'PROOF' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const location = useLocation();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}. I'm here to handle your grievance. Tell me, what issue are you facing?` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [analysis, setAnalysis] = useState<any>(null);
  const [currentAttachments, setCurrentAttachments] = useState<Attachment[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reset chat if user navigates to the page again
  useEffect(() => {
    if (location.pathname === '/' && state === 'DONE') {
      handleReset();
    }
  }, [location]);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const handleReset = () => {
    setState('IDLE');
    setMessages([{ role: 'assistant', content: `Hello ${currentUser?.name}. How can I assist you with a grievance today?` }]);
    setAnalysis(null);
    setCurrentAttachments([]);
  };

  const addBotMessage = (content: string, attachments?: Attachment[]) => {
    setMessages(prev => [...prev, { role: 'assistant', content, attachments }]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = ev.target?.result as string;
        setCurrentAttachments(prev => [...prev, { name: file.name, type: file.type, data: base64 }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'IDLE' || state === 'COLLECTING') {
      try {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you specify the location and time of this incident?");
        } else {
          if (result.isSensitive && currentAttachments.length === 0) {
            setState('PROOF');
            addBotMessage("This is a serious matter. Please upload any photos, audio, or documents as proof using the attachment icon. If you have none, just say 'No proof'.");
          } else {
            setState('REVIEW');
            addBotMessage(`Format Complete. Summary: **${result.summary}**\n\nRouting to **${result.department}** (${result.severity} Priority). \n\nIs this correct? Say "Yes" to submit.`);
          }
        }
      } catch (err) {
        const fallback = await getBotResponse(messages, userMessage);
        addBotMessage(fallback || "I'm listening. Please describe the problem clearly.");
      }
    } 

    else if (state === 'PROOF') {
      setState('REVIEW');
      addBotMessage(`Summary: **${analysis.summary}**\n\nRouting to **${analysis.department}**. Correct? Say "Yes" to submit.`);
    }

    else if (state === 'REVIEW') {
      if (/yes|ok|correct|submit/i.test(userMessage)) {
        finalizeGrievance();
      } else {
        addBotMessage("Understood. What details should I change?");
        setState('COLLECTING');
      }
    }

    setIsTyping(false);
  };

  const finalizeGrievance = () => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n---\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'in-app',
        timestamp: now,
        message: `Case registered and assigned to ${staff?.name}.`
      }],
      attachments: currentAttachments
    };

    saveGrievance(newGrievance);
    addBotMessage(`Grievance Logged. \n\n**Reference ID: ${grievanceId}**\nAssigned to: ${staff?.name}.\n\nYou can track updates in "My Grievances".`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && currentAttachments.length === 0) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg, attachments: currentAttachments }]);
    setInput('');
    // Attachment handled by state update but cleared from current for next msg
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] gap-4">
      {/* Progress Checklist */}
      {state !== 'IDLE' && state !== 'DONE' && analysis && (
        <div className="bg-white rounded-3xl p-6 shadow-xl border-b-4 border-indigo-600 flex flex-wrap gap-4 items-center justify-between animate-in fade-in slide-in-from-top-2">
           <div className="flex gap-4">
              <div className="flex items-center gap-2">
                <div className={`w-4 h-4 rounded-full flex items-center justify-center text-[10px] text-white ${analysis.isDetailedEnough ? 'bg-emerald-500' : 'bg-slate-200'}`}>
                  {analysis.isDetailedEnough ? '✓' : '1'}
                </div>
                <span className={`text-[10px] font-black uppercase tracking-widest ${analysis.isDetailedEnough ? 'text-emerald-600' : 'text-slate-400'}`}>Facts</span>
              </div>
              <div className="flex items-center gap-2">
                <div className={`w-4 h-4 rounded-full flex items-center justify-center text-[10px] text-white ${state === 'PROOF' || currentAttachments.length > 0 ? 'bg-indigo-500' : 'bg-slate-200'}`}>
                  {currentAttachments.length > 0 ? '✓' : '2'}
                </div>
                <span className={`text-[10px] font-black uppercase tracking-widest ${currentAttachments.length > 0 ? 'text-indigo-600' : 'text-slate-400'}`}>Evidence</span>
              </div>
              <div className="flex items-center gap-2">
                <div className={`w-4 h-4 rounded-full flex items-center justify-center text-[10px] text-white ${state === 'REVIEW' ? 'bg-orange-500' : 'bg-slate-200'}`}>3</div>
                <span className={`text-[10px] font-black uppercase tracking-widest ${state === 'REVIEW' ? 'text-orange-600' : 'text-slate-400'}`}>Submit</span>
              </div>
           </div>
           {analysis.missingPoints?.length > 0 && (
             <div className="text-[9px] font-bold text-red-500 bg-red-50 px-3 py-1 rounded-full uppercase tracking-tighter">
               Missing: {analysis.missingPoints[0]}
             </div>
           )}
        </div>
      )}

      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-8 bg-slate-900 flex items-center justify-between text-white border-b-4 border-indigo-600">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-xl font-black">EduResolve AI</h2>
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                 <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Grievance Assistant</p>
              </div>
            </div>
          </div>
          <div className="flex flex-col items-end gap-2">
            <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-xl border border-white/10">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Incognito</span>
              <button 
                onClick={() => setIsAnonymous(!isAnonymous)}
                className={`w-10 h-5 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-700'}`}
              >
                <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all ${isAnonymous ? 'left-5.5' : 'left-0.5'}`}></div>
              </button>
            </div>
          </div>
        </div>

        {/* Chat Stream */}
        <div className="flex-1 overflow-y-auto p-10 space-y-6 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
              <div className={`max-w-[85%] ${
                msg.role === 'user' ? 'bg-slate-900 text-white rounded-3xl rounded-tr-none shadow-xl' : 'bg-white text-slate-900 border-2 border-slate-100 rounded-3xl rounded-tl-none'
              } p-6`}>
                <p className="text-[14px] font-bold leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-4 flex flex-wrap gap-2">
                    {msg.attachments.map((at, idx) => (
                      <div key={idx} className="bg-slate-800/20 p-2 rounded-xl border border-slate-200 flex items-center gap-2 max-w-xs">
                         <span className="text-[9px] font-black uppercase text-indigo-700 truncate">{at.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && <div className="p-4 bg-white border-2 border-slate-100 rounded-2xl w-max animate-pulse font-black text-[10px] text-indigo-600 uppercase">Analyzing Input...</div>}
          <div ref={scrollRef}></div>
        </div>

        {/* Footer Dock */}
        <div className="p-8 bg-white border-t-4 border-slate-50">
          {currentAttachments.length > 0 && (
            <div className="mb-4 flex flex-wrap gap-2">
               {currentAttachments.map((at, i) => (
                 <div key={i} className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-full text-[10px] font-black border border-indigo-100 flex items-center gap-2">
                    {at.name} <button onClick={() => setCurrentAttachments(prev => prev.filter((_, idx) => idx !== i))}>✕</button>
                 </div>
               ))}
            </div>
          )}
          <form onSubmit={handleSubmit} className="flex gap-4">
            <button 
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple />

            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Grievance Logged." : "Type your response..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-2 border-slate-200 rounded-2xl px-6 py-4 text-slate-900 font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all"
            />
            <button
              type="submit"
              disabled={(!input.trim() && currentAttachments.length === 0) || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-14 h-14 rounded-2xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-xl disabled:opacity-30"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
          {state === 'DONE' && (
            <button onClick={handleReset} className="mt-4 w-full py-4 bg-slate-100 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 hover:text-indigo-600 transition-all">Start New Session</button>
          )}
        </div>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

