import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

export const analyzeGrievanceState = async (text: string, history: { role: string; content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Full Conversation History: ${JSON.stringify(history)}\nNew User Message: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: {
            type: Type.BOOLEAN,
            description: "True if what, where, and when are clearly stated.",
          },
          missingPoints: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of missing details as short bullet points.",
          },
          followUpQuestion: {
            type: Type.STRING,
            description: "A VERY SHORT question (max 10 words) to get the next missing piece.",
          },
          isSensitive: {
            type: Type.BOOLEAN,
            description: "True if the issue involves safety, harassment, or high-value damage.",
          },
          department: {
            type: Type.STRING,
            description: "Hostel, Mess/Food, Academics, Administration, Hygiene, Electrical, or Other.",
          },
          severity: {
            type: Type.STRING,
            description: "Low, Medium, High, or Critical.",
          },
          summary: {
            type: Type.STRING,
            description: "A one-sentence recap of the complaint facts.",
          }
        },
        required: ["isDetailedEnough", "missingPoints", "followUpQuestion", "isSensitive", "department", "severity", "summary"],
      },
      systemInstruction: "You are a smart grievance processor. Your output must be used to guide a step-by-step process. 1. Identify the issue. 2. Identify Location/Time. 3. Ask for evidence if sensitive. Always be brief. If details are missing, your followUpQuestion should be direct. Use the missingPoints array to store exactly what is still needed.",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));
  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are EduResolve AI. Respond in 1-2 short sentences maximum. Use bullet points if listing anything. Be extremely concise.",
    },
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { analyzeGrievanceState, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'PROOF' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}. I'm here to help. To start your grievance, please describe exactly what happened.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAnonymous, setIsAnonymous] = useState(true);
  const [analysis, setAnalysis] = useState<any>(null);
  const [currentAttachments, setCurrentAttachments] = useState<Attachment[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleResetEvent = () => handleReset();
    window.addEventListener('reset-grievance-chat', handleResetEvent);
    return () => window.removeEventListener('reset-grievance-chat', handleResetEvent);
  }, []);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const handleReset = () => {
    setState('IDLE');
    setMessages([{ role: 'assistant', content: `Chat Reset. Hello ${currentUser?.name}, what is the issue today?` }]);
    setAnalysis(null);
    setCurrentAttachments([]);
    setInput('');
  };

  const addBotMessage = (content: string, attachments?: Attachment[]) => {
    setMessages(prev => [...prev, { role: 'assistant', content, attachments }]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = ev.target?.result as string;
        setCurrentAttachments(prev => [...prev, { name: file.name, type: file.type, data: base64 }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'IDLE' || state === 'COLLECTING') {
      try {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          const missing = result.missingPoints?.length > 0 
            ? `\n\nI still need the following:\n${result.missingPoints.map((p: string) => `• ${p}`).join('\n')}`
            : '';
          addBotMessage(`${result.followUpQuestion || "Can you provide more details?"}${missing}`);
        } else {
          if (result.isSensitive && currentAttachments.length === 0) {
            setState('PROOF');
            addBotMessage("### Step 2: Verification\nThis matter requires evidence. Please attach photos or audio. If you don't have any, type 'Skip'.");
          } else {
            setState('REVIEW');
            addBotMessage(`### Step 3: Confirmation\n**Summary:** ${result.summary}\n**Dept:** ${result.department}\n**Priority:** ${result.severity}\n\nShall I submit this now? (Yes/No)`);
          }
        }
      } catch (err) {
        const fallback = await getBotResponse(messages, userMessage);
        addBotMessage(fallback || "I'm listening. Please be specific about the problem.");
      }
    } 

    else if (state === 'PROOF') {
      setState('REVIEW');
      addBotMessage(`### Final Review\n**Summary:** ${analysis.summary}\n**Department:** ${analysis.department}\n\nSubmit this grievance?`);
    }

    else if (state === 'REVIEW') {
      if (/yes|ok|correct|submit|go/i.test(userMessage)) {
        finalizeGrievance();
      } else {
        addBotMessage("Okay, let's start over. What is the issue?");
        setState('IDLE');
      }
    }

    setIsTyping(false);
  };

  const finalizeGrievance = () => {
    const grievanceId = 'REF-' + Math.random().toString(36).substring(2, 7).toUpperCase();
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const newGrievance: Grievance = {
      id: grievanceId,
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n---\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.SUBMITTED,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.SUBMITTED, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [{
        type: 'in-app',
        timestamp: now,
        message: `Grievance #${grievanceId} successfully routed to ${dept} department.`
      }],
      attachments: currentAttachments
    };

    saveGrievance(newGrievance);
    addBotMessage(`### Submission Success\n**Reference ID:** \`${grievanceId}\`\n**Assigned To:** ${staff?.name}\n\nTrack this in your dashboard anytime.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && currentAttachments.length === 0) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg, attachments: currentAttachments }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] gap-4">
      {/* Visual Sequence Indicator */}
      {state !== 'IDLE' && state !== 'DONE' && (
        <div className="bg-white rounded-3xl p-5 shadow-lg flex items-center justify-center gap-10 border-b-4 border-indigo-600">
           {[
             { id: 'COLLECTING', label: 'Details' },
             { id: 'PROOF', label: 'Evidence' },
             { id: 'REVIEW', label: 'Confirm' }
           ].map((step, idx) => {
             const active = state === step.id || (idx === 0 && state === 'COLLECTING');
             const done = (idx === 0 && (state === 'PROOF' || state === 'REVIEW')) || (idx === 1 && state === 'REVIEW');
             return (
               <div key={step.id} className="flex items-center gap-3">
                 <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black ${
                   done ? 'bg-emerald-500 text-white' : active ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'
                 }`}>
                   {done ? '✓' : idx + 1}
                 </div>
                 <span className={`text-[10px] font-black uppercase tracking-widest ${active || done ? 'text-slate-900' : 'text-slate-300'}`}>
                   {step.label}
                 </span>
               </div>
             )
           })}
        </div>
      )}

      <div className="bg-white rounded-[40px] shadow-2xl border-4 border-slate-100 flex-1 flex flex-col overflow-hidden">
        <div className="p-6 bg-slate-900 flex items-center justify-between text-white border-b-4 border-indigo-600">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg">
              <ICONS.Bot />
            </div>
            <div>
              <h2 className="text-lg font-black tracking-tight">EduResolve AI</h2>
              <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Processing Inquiry</p>
            </div>
          </div>
          <div className="flex items-center gap-3 bg-white/5 px-4 py-2 rounded-xl border border-white/10">
            <span className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Incognito</span>
            <button 
              onClick={() => setIsAnonymous(!isAnonymous)}
              className={`w-10 h-5 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-700'}`}
            >
              <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all ${isAnonymous ? 'left-5.5' : 'left-0.5'}`}></div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-10 space-y-6 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] ${
                msg.role === 'user' ? 'bg-slate-900 text-white rounded-3xl rounded-tr-none shadow-xl' : 'bg-white text-slate-900 border-2 border-slate-100 rounded-3xl rounded-tl-none'
              } p-6 shadow-sm`}>
                <div className="text-[14px] font-bold leading-relaxed whitespace-pre-wrap">
                   {msg.content.split('\n').map((line, idx) => (
                     <p key={idx} className={line.startsWith('#') ? "text-indigo-600 font-black mb-2" : "mb-1"}>{line}</p>
                   ))}
                </div>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-4 flex flex-wrap gap-2">
                    {msg.attachments.map((at, idx) => (
                      <div key={idx} className="bg-slate-800/20 p-2 rounded-xl border border-slate-200 flex items-center gap-2 max-w-xs">
                         <span className="text-[9px] font-black uppercase text-indigo-700 truncate">{at.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && <div className="px-5 py-3 bg-white border-2 border-slate-100 rounded-2xl w-max animate-pulse font-black text-[9px] text-indigo-600 uppercase">Evaluating Details...</div>}
          <div ref={scrollRef}></div>
        </div>

        <div className="p-8 bg-white border-t-4 border-slate-50">
          {currentAttachments.length > 0 && (
            <div className="mb-4 flex flex-wrap gap-2">
               {currentAttachments.map((at, i) => (
                 <div key={i} className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-full text-[9px] font-black border border-indigo-100 flex items-center gap-2">
                    {at.name} <button onClick={() => setCurrentAttachments(prev => prev.filter((_, idx) => idx !== i))}>✕</button>
                 </div>
               ))}
            </div>
          )}
          <form onSubmit={handleSubmit} className="flex gap-4">
            <button 
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="w-14 h-14 bg-slate-100 text-slate-500 rounded-2xl flex items-center justify-center hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple />

            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Session Completed." : "Provide specific details..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-100 border-2 border-slate-200 rounded-2xl px-6 py-4 text-slate-900 font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all"
            />
            <button
              type="submit"
              disabled={(!input.trim() && currentAttachments.length === 0) || isTyping || state === 'DONE'}
              className="bg-indigo-600 text-white w-14 h-14 rounded-2xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-xl disabled:opacity-30"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </form>
          {state === 'DONE' && (
            <button onClick={handleReset} className="mt-4 w-full py-4 bg-slate-100 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 hover:text-indigo-600 transition-all">Start New Session</button>
          )}
        </div>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import React, { useState, useEffect } from 'react';
import { findGrievanceById, MOCK_USERS, getMyGrievances, getCurrentUser } from '../store';
import { Grievance, Status } from '../types';
import { COLORS } from '../constants';

const GrievanceTracker: React.FC = () => {
  const currentUser = getCurrentUser();
  const [searchId, setSearchId] = useState('');
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [myList, setMyList] = useState<Grievance[]>([]);
  const [error, setError] = useState('');

  useEffect(() => {
    if (currentUser?.id) {
      setMyList(getMyGrievances(currentUser.id));
    }
  }, [currentUser?.id]); // Fix: Use primitive ID to prevent infinite re-render loop

  const handleSearch = (e?: React.FormEvent, manualId?: string) => {
    if (e) e.preventDefault();
    const id = (manualId || searchId.trim()).toUpperCase();
    const found = findGrievanceById(id);
    if (found) {
      setGrievance(found);
      setError('');
    } else {
      setGrievance(null);
      setError('Grievance Ref Not Found.');
    }
  };

  const statusSteps = [
    { s: Status.SUBMITTED, label: 'Submitted', icon: 'M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z' },
    { s: Status.IN_REVIEW, label: 'Reviewing', icon: 'M15 12a3 3 0 11-6 0 3 3 0 016 0z M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z' },
    { s: Status.ASSIGNED, label: 'Assigned', icon: 'M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z' },
    { s: Status.IN_PROGRESS, label: 'In Progress', icon: 'M13 10V3L4 14h7v7l9-11h-7z' },
    { s: Status.RESOLVED, label: 'Resolved', icon: 'M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z' }
  ];

  const currentIdx = grievance ? statusSteps.findIndex(x => x.s === grievance.status) : -1;
  const assignedStaff = grievance ? MOCK_USERS.find(u => u.id === grievance.assignedToId) : null;

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="text-center space-y-3">
        <h2 className="text-3xl font-black text-slate-900">Your Complaints</h2>
        <p className="text-slate-900 font-bold uppercase tracking-widest text-[10px]">Track resolution progress</p>
      </div>

      <div className="bg-white p-8 rounded-[32px] shadow-xl border-2 border-slate-200">
        <form onSubmit={(e) => handleSearch(e)} className="flex gap-4">
          <input
            type="text"
            value={searchId}
            onChange={(e) => setSearchId(e.target.value)}
            placeholder="REF-XXXX"
            className="flex-1 bg-slate-50 border-2 border-slate-200 rounded-2xl px-6 py-4 focus:border-indigo-600 outline-none text-slate-900 font-black uppercase tracking-widest"
          />
          <button type="submit" className="bg-indigo-600 text-white px-10 rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all">Track</button>
        </form>
        {error && <p className="text-red-700 text-xs mt-3 font-black uppercase tracking-wider ml-2">{error}</p>}
      </div>

      {!grievance && myList.length > 0 && (
        <div className="space-y-4">
          <h3 className="text-[11px] font-black text-slate-600 uppercase tracking-[0.2em] ml-2">My History</h3>
          <div className="grid grid-cols-1 gap-4">
            {myList.map(item => (
              <button 
                key={item.id}
                onClick={() => handleSearch(undefined, item.id)}
                className="bg-white p-6 rounded-3xl border-2 border-slate-200 hover:border-indigo-500 transition-all text-left flex justify-between items-center group shadow-md"
              >
                <div>
                  <p className="text-[10px] font-black text-indigo-700 uppercase tracking-widest mb-1">{item.department}</p>
                  <p className="font-black text-slate-900 uppercase tracking-widest text-lg">#{item.id}</p>
                </div>
                <div className="text-right">
                  <span className={`text-[10px] font-black px-4 py-2 rounded-xl uppercase shadow-sm ${COLORS.status[item.status]}`}>
                    {item.status}
                  </span>
                  <p className="text-[9px] font-bold text-slate-700 mt-2 uppercase">Updated {new Date(item.lastStatusChange).toLocaleDateString()}</p>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      {grievance && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-300">
          <button 
            onClick={() => setGrievance(null)}
            className="text-[11px] font-black text-indigo-700 uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-50 w-max px-5 py-3 rounded-2xl border-2 border-transparent hover:border-indigo-100 transition-all"
          >
            &larr; Back to List
          </button>

          <div className="bg-slate-900 rounded-[32px] p-10 text-white shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
              <p className="text-indigo-400 text-xs font-black uppercase tracking-[0.2em] mb-4">Live Progress Status</p>
              <h3 className="text-4xl font-black mb-8 uppercase tracking-tight">{grievance.status}</h3>
              <div className="flex flex-wrap gap-4 items-center">
                <span className="text-[10px] bg-white/20 px-5 py-2.5 rounded-full font-black uppercase tracking-widest border border-white/10">Ref: {grievance.id}</span>
                <span className={`text-[10px] px-5 py-2.5 rounded-full font-black uppercase tracking-widest ${COLORS.severity[grievance.severity]}`}>
                  {grievance.severity} Priority
                </span>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-[32px] shadow-xl border-2 border-slate-200 p-10">
            <div className="space-y-12">
              {statusSteps.map((step, idx) => {
                const isCompleted = idx <= currentIdx;
                const isLast = idx === statusSteps.length - 1;
                const isCurrent = idx === currentIdx;

                return (
                  <div key={idx} className="flex gap-10 relative">
                    {!isLast && (
                      <div className={`absolute left-6 top-12 w-1.5 h-full -ml-[3px] rounded-full ${isCompleted ? 'bg-indigo-600' : 'bg-slate-100'}`}></div>
                    )}
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center flex-shrink-0 z-10 transition-all ${
                      isCompleted ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-100 text-slate-400'
                    } ${isCurrent ? 'ring-8 ring-indigo-50 scale-110' : ''}`}>
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d={step.icon} /></svg>
                    </div>
                    <div className="flex-1 pb-6">
                      <h4 className={`text-xl font-black ${isCompleted ? 'text-slate-900' : 'text-slate-300'}`}>{step.label}</h4>
                      {isCurrent && (
                        <div className="mt-3 flex items-center gap-3">
                           <span className="flex h-2 w-2 rounded-full bg-indigo-600 animate-ping"></span>
                           <p className="text-xs text-indigo-700 font-black uppercase">Current Stage</p>
                        </div>
                      )}
                      {grievance.history.find(h => h.status === step.s) && (
                         <p className="text-[11px] text-slate-900 mt-3 font-bold bg-slate-100 inline-block px-4 py-1.5 rounded-xl border border-slate-200">
                           {new Date(grievance.history.find(h => h.status === step.s)!.timestamp).toLocaleString()}
                         </p>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GrievanceTracker;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { getCurrentUser, logout } from '../store';
import { UserRole } from '../types';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [currentUser, setUser] = useState(getCurrentUser());

  useEffect(() => {
    const handleStorage = () => setUser(getCurrentUser());
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const handleNavClick = (path: string) => {
    if (path === '/' && location.pathname === '/') {
      window.dispatchEvent(new Event('reset-grievance-chat'));
    }
  };

  if (!currentUser) return <>{children}</>;

  const navItems = [
    { path: '/', label: 'Submit Grievance', roles: [UserRole.STUDENT] },
