    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = ev.target?.result as string;
        setCurrentAttachments(prev => [...prev, { name: file.name, type: file.type, data: base64 }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);

    if (state === 'IDLE' || state === 'COLLECTING') {
      try {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you provide more specific details?");
        } else {
          if (result.isSensitive && currentAttachments.length === 0) {
            setState('PROOF');
            addBotMessage("Verification required: Please upload any supporting evidence (photos/audio). Type 'None' to skip.");
          } else {
            setState('REVIEW');
            addBotMessage(`Review Summary:\n\n**Category:** ${result.department}\n**Priority:** ${result.severity.toUpperCase()}\n\nProceed with submission?`);
          }
        }
      } catch (err) {
        const fallback = await getBotResponse(messages, userMessage);
        addBotMessage(fallback || "I'm processing your request. Please continue.");
      }
    } 

    else if (state === 'PROOF') {
      setState('REVIEW');
      addBotMessage(`Summary validated. Submit this to the ${analysis?.department} department?`);
    }

    else if (state === 'REVIEW') {
      if (/yes|ok|correct|submit/i.test(userMessage)) {
        finalizeGrievance();
      } else {
        addBotMessage("Cancelled. How should I adjust the complaint?");
        setState('COLLECTING');
      }
    }

    setIsTyping(false);
  };

  const finalizeGrievance = () => {
    const grievanceId = 'CMP-' + Math.floor(100 + Math.random() * 900);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = getResponsibleStaffId(dept);
    const staff = MOCK_USERS.find(u => u.id === staffId);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary?.slice(0, 50) + '...',
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      attachments: currentAttachments
    };

    saveGrievance(newGrievance);
    addBotMessage(`Submission Successful. Reference ID: **${grievanceId}**.\n\nAssigned to ${staff?.name}. Tracking active.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && currentAttachments.length === 0) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg, attachments: currentAttachments }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 flex flex-col h-[calc(100vh-12rem)]">
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between p-6">
         <div className="flex gap-8">
            {[
              { label: 'Details', id: 'COLLECTING' },
              { label: 'Evidence', id: 'PROOF' },
              { label: 'Review', id: 'REVIEW' }
            ].map((step, idx) => {
               const active = state === step.id || (idx === 0 && state === 'COLLECTING') || (state === 'IDLE' && idx === 0);
               const done = (idx === 0 && (state === 'PROOF' || state === 'REVIEW' || state === 'DONE')) || (idx === 1 && (state === 'REVIEW' || state === 'DONE')) || (idx === 2 && state === 'DONE');
               return (
                 <div key={idx} className="flex items-center gap-3">
                    <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black ${done ? 'bg-emerald-500 text-white' : active ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                       {done ? '✓' : idx + 1}
                    </div>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${active || done ? 'text-slate-900' : 'text-slate-300'}`}>{step.label}</span>
                 </div>
               )
            })}
         </div>
         <div className="flex items-center gap-3 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100">
            <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Anonymous Mode</span>
            <button onClick={() => setIsAnonymous(!isAnonymous)} className={`w-8 h-4 rounded-full transition-all relative ${isAnonymous ? 'bg-indigo-500' : 'bg-slate-300'}`}>
              <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${isAnonymous ? 'left-4.5' : 'left-0.5'}`}></div>
            </button>
         </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm flex-1 flex flex-col overflow-hidden">
        <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-slate-50/20">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[75%] p-6 rounded-2xl ${msg.role === 'user' ? 'bg-slate-950 text-white rounded-tr-none' : 'bg-white border border-slate-200 text-slate-900 rounded-tl-none shadow-sm'}`}>
                <p className="text-sm font-medium leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                {msg.attachments && msg.attachments.length > 0 && (
                  <div className="mt-4 flex flex-wrap gap-2">
                    {msg.attachments.map((at, idx) => (
                      <div key={idx} className="bg-slate-800/10 px-3 py-1.5 rounded-lg border border-slate-200 flex items-center gap-2">
                         <span className="text-[10px] font-bold text-indigo-700 truncate">{at.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && <div className="px-5 py-3 bg-white border border-slate-200 rounded-xl w-max animate-pulse font-bold text-[10px] text-slate-400 uppercase tracking-widest">Bot is typing...</div>}
          <div ref={scrollRef}></div>
        </div>

        <div className="p-8 bg-white border-t border-slate-100">
          <form onSubmit={handleSubmit} className="flex gap-4">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-12 h-12 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center hover:bg-slate-100 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={state === 'DONE' ? "Session completed." : "Type your details..."}
              disabled={state === 'DONE' || isTyping}
              className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-6 py-3 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
            />
            <button type="submit" disabled={!input.trim() || isTyping || state === 'DONE'} className="bg-slate-950 text-white px-8 py-3 rounded-xl font-bold text-sm hover:bg-slate-800 transition-all disabled:opacity-20 shadow-md">
              Send
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

