export const getResponsibleStaffId = (dept: Department): string => {
  const staff = MOCK_USERS.find(u => u.department === dept);
  return staff ? staff.id : 'ADM-ADMIN';
};

export const isAuthenticated = (): boolean => localStorage.getItem(AUTH_KEY) === 'true';

export const getCurrentUser = (): User | null => {
  if (!isAuthenticated()) return null;
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : null;
};

export const login = (userId: string, password: string): boolean => {
  const user = MOCK_USERS.find(u => u.id === userId && u.password === password);
  if (user) {
    const { password: _, ...userData } = user;
    localStorage.setItem(USER_KEY, JSON.stringify(userData));
    localStorage.setItem(AUTH_KEY, 'true');
    window.dispatchEvent(new Event('storage'));
    return true;
  }
  return false;
};

export const logout = () => {
  localStorage.removeItem(USER_KEY);
  localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('storage'));
};

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(GRIEVANCE_KEY);
  return data ? JSON.parse(data) : [];
};

export const getMyGrievances = (userId: string): Grievance[] => {
  return getGrievances().filter(g => g.studentId === userId);
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();
  localStorage.setItem(GRIEVANCE_KEY, JSON.stringify([...current, grievance]));
};

export const updateGrievance = (updatedG: Grievance) => {
  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    const oldStatus = current[index].status;
    if (oldStatus !== updatedG.status) {
      // Fix: Ensure notificationsSent is initialized if it was missing from storage
      if (!updatedG.notificationsSent) {
        updatedG.notificationsSent = [];
      }
      updatedG.notificationsSent.push({
        type: 'email',
        timestamp: Date.now(),
        message: `Official Notice: Grievance #${updatedG.id} updated to ${updatedG.status.toUpperCase()}.`
      });
    }
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

export const findGrievanceById = (id: string) => getGrievances().find(g => g.id === id);

