const GrievanceTracker: React.FC = () => {
  const user = getCurrentUser();
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');

  const complaints = useMemo(() => {
    if (!user) return [];
    return getMyGrievances(user.id).filter(g => {
      const matchSearch = g.id.toLowerCase().includes(search.toLowerCase()) || (g.title || '').toLowerCase().includes(search.toLowerCase());
      const matchStatus = filterStatus === 'all' || g.status === filterStatus;
      const matchCategory = filterCategory === 'all' || g.department === filterCategory;
      return matchSearch && matchStatus && matchCategory;
    });
  }, [user, search, filterStatus, filterCategory]);

  if (!user) return null;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">My Complaints</h2>
          <p className="text-sm text-slate-500 mt-1">Track and manage all your submitted complaints</p>
        </div>
        <button className="flex items-center gap-2 bg-slate-950 text-white px-5 py-3 rounded-xl font-bold text-sm hover:bg-slate-800 transition-all">
          <ICONS.Raise />
          New Complaint
        </button>
      </div>

      <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm space-y-8">
        <h3 className="font-bold text-slate-900">Filters</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="relative">
             <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-slate-400"><ICONS.Search /></div>
             <input 
                type="text" 
                placeholder="Search complaints..." 
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-12 pr-6 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium" 
             />
          </div>
          <select 
            value={filterStatus}
            onChange={e => setFilterStatus(e.target.value)}
            className="bg-slate-50 border border-slate-200 rounded-xl px-6 py-3 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 appearance-none"
          >
            <option value="all">All Status</option>
            {Object.values(Status).map(s => <option key={s} value={s}>{s.replace('-', ' ')}</option>)}
          </select>
          <select 
             value={filterCategory}
             onChange={e => setFilterCategory(e.target.value)}
             className="bg-slate-50 border border-slate-200 rounded-xl px-6 py-3 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 appearance-none"
          >
            <option value="all">All Categories</option>
            {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100 text-xs font-bold text-slate-500 uppercase tracking-wider">
              <tr>
                <th className="px-8 py-5">ID</th>
                <th className="px-8 py-5">Title</th>
                <th className="px-8 py-5">Category</th>
                <th className="px-8 py-5">Priority</th>
                <th className="px-8 py-5">Status</th>
                <th className="px-8 py-5">Created</th>
                <th className="px-8 py-5 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {complaints.length === 0 ? (
                <tr><td colSpan={7} className="px-8 py-20 text-center text-slate-400 font-medium italic">No complaints matching filters</td></tr>
              ) : (
                complaints.map(g => (
                  <tr key={g.id} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-5 font-bold text-slate-900 text-sm">{g.id}</td>
                    <td className="px-8 py-5 text-sm font-medium text-slate-600">{g.title || 'General Grievance'}</td>
                    <td className="px-8 py-5"><span className="text-xs font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">{g.department}</span></td>
                    <td className="px-8 py-5"><span className={`text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-tighter ${COLORS.severity[g.severity]}`}>{g.severity}</span></td>
                    <td className="px-8 py-5"><span className={`text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-tighter ${COLORS.status[g.status]}`}>{g.status.replace('-', ' ')}</span></td>
                    <td className="px-8 py-5 text-sm font-medium text-slate-500">{new Date(g.timestamp).toLocaleDateString()}</td>
                    <td className="px-8 py-5 text-right">
                      <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
        <div className="p-8 bg-slate-50/50 border-t border-slate-100 flex items-center justify-between">
           <p className="text-sm text-slate-500 font-medium">Showing {complaints.length} of {complaints.length} complaints</p>
           <div className="flex gap-2">
              <button disabled className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-bold text-slate-400 disabled:opacity-50">Previous</button>
              <button disabled className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-bold text-slate-400 disabled:opacity-50">Next</button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default GrievanceTracker;

import React, { useMemo } from 'react';
