          { label: user.role === UserRole.STUDENT ? 'In Progress' : 'Overdue', value: stats.inProgress, color: 'text-indigo-600', icon: 'M7 12l3-3 3 3M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z' },
