export const getResponsibleStaffId = (dept: Department): string => {
  const staff = MOCK_USERS.find(u => u.department === dept);
  return staff ? staff.id : 'ADM-PRIN';
};

export const isAuthenticated = (): boolean => localStorage.getItem(AUTH_KEY) === 'true';

export const getCurrentUser = (): User | null => {
  if (!isAuthenticated()) return null;
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : null;
};

export const login = (userId: string, password: string): boolean => {
  const user = MOCK_USERS.find(u => (u.id === userId || u.email === userId) && u.password === password);
  if (user) {
    const { password: _, ...userData } = user;
    localStorage.setItem(USER_KEY, JSON.stringify(userData));
    localStorage.setItem(AUTH_KEY, 'true');
    window.dispatchEvent(new Event('storage'));
    return true;
  }
  return false;
};

export const logout = () => {
  localStorage.removeItem(USER_KEY);
  localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('storage'));
};

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(GRIEVANCE_KEY);
  const grievances: Grievance[] = data ? JSON.parse(data) : [];

  // Escalation Check Logic (Simulated cron)
  const ONE_WEEK_MS = 7 * 24 * 60 * 60 * 1000;
  const now = Date.now();
  let changed = false;

  const escalated = grievances.map(g => {
    if (g.status !== Status.RESOLVED && g.status !== Status.CLOSED && (now - g.timestamp > ONE_WEEK_MS)) {
      if (!g.notificationsSent.some(n => n.message.includes('ESCALATED'))) {
        g.notificationsSent.push({
          type: 'alert',
          timestamp: now,
          message: 'CRITICAL: ESCALATED TO PRINCIPAL - Case unresolved for over 1 week.'
        });
        // Reassign to principal in case of total failure
        g.assignedToId = 'ADM-PRIN';
        changed = true;
      }
    }
    return g;
  });

  if (changed) {
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(escalated));
    return escalated;
  }

  return grievances;
};

export const getMyGrievances = (userId: string): Grievance[] => {
  return getGrievances().filter(g => g.studentId === userId);
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();
  localStorage.setItem(GRIEVANCE_KEY, JSON.stringify([...current, grievance]));
};

export const updateGrievance = (updatedG: Grievance) => {
  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

export const findGrievanceById = (id: string) => getGrievances().find(g => g.id === id);

import { GoogleGenAI, Type } from "@google/genai";
import { Department, Severity } from "../types";

export const analyzeGrievanceState = async (text: string, history: { role: string; content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Full Conversation History: ${JSON.stringify(history)}\nNew User Message: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: {
            type: Type.BOOLEAN,
            description: "True if what, where, and when are clearly stated.",
          },
          missingPoints: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of missing details as short bullet points.",
          },
          followUpQuestion: {
            type: Type.STRING,
            description: "A VERY SHORT question (max 10 words) to get the next missing piece.",
          },
          isSensitive: {
            type: Type.BOOLEAN,
            description: "True if the issue involves safety, harassment, or high-value damage.",
          },
          department: {
            type: Type.STRING,
            description: "Hostel, Mess, Academics, Infrastructure, Transport, or Other.",
          },
          severity: {
            type: Type.STRING,
            description: "Low, Medium, High, or Critical.",
          },
          summary: {
            type: Type.STRING,
            description: "A one-sentence recap of the complaint facts.",
          }
        },
        required: ["isDetailedEnough", "missingPoints", "followUpQuestion", "isSensitive", "department", "severity", "summary"],
      },
      systemInstruction: "You are a smart grievance processor. Your output must be used to guide a step-by-step process. Be extremely brief.",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getBotResponse = async (history: { role: string; content: string }[], currentInput: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contents = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));
  contents.push({ role: 'user', parts: [{ text: currentInput }] });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents as any,
    config: {
      systemInstruction: "You are EduResolve AI. Respond in 1-2 short sentences maximum. Use bullet points if listing anything. Be extremely concise.",
    },
  });

  return response.text;
};

export const getStaffAssistance = async (caseDescription: string, userQuery: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Case Description: ${caseDescription}\nStaff Member Query: ${userQuery}`,
    config: {
      systemInstruction: "You are a Case Analyst for institution staff. Summarize the grievance objectively and suggest 2-3 professional resolution steps or identifying which department should handle it if misassigned. Keep it under 100 words.",
    },
  });

  return response.text;
};

import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getGrievances, updateGrievance, getCurrentUser, MOCK_USERS, getResponsibleStaffId } from '../store';
import { Grievance, Status, UserRole, Department, COLORS } from '../types';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [remarkInput, setRemarkInput] = useState('');
  const [statusInput, setStatusInput] = useState<Status | ''>('');
  const [reassignDept, setReassignDept] = useState<Department | ''>('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const id = location.state?.grievanceId;
    if (id) {
      const g = getGrievances().find(x => x.id === id);
      if (g) {
        setGrievance(g);
        setStatusInput(g.status);
      }
    }
  }, [location.state]);

  const handleUpdate = () => {
    if (!grievance || !currentUser) return;

    const now = Date.now();
    const updated: Grievance = { ...grievance };

    if (reassignDept && reassignDept !== grievance.department) {
      const newStaffId = getResponsibleStaffId(reassignDept);
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: `Reassigned from ${grievance.department} to ${reassignDept}. ${remarkInput}`,
        reassignedFrom: grievance.department,
        reassignedTo: reassignDept
      });
      updated.department = reassignDept;
      updated.assignedToId = newStaffId;
      updated.remarks.push(`REASSIGNED: ${remarkInput}`);
    } else {
      updated.status = (statusInput as Status) || updated.status;
      updated.lastStatusChange = now;
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: remarkInput
      });
      if (remarkInput) updated.remarks.push(remarkInput);
    }

    updateGrievance(updated);
    navigate('/dashboard');
  };

  const askAi = async () => {
    if (!grievance) return;
    setIsAiLoading(true);
    try {
      const res = await getStaffAssistance(grievance.description, "Summarize this case and suggest next steps for resolution.");
      setAiResponse(res || 'No response from AI.');
    } catch (e) {
      setAiResponse('AI Service unavailable.');
    } finally {
      setIsAiLoading(false);
    }
  };

  if (!grievance || !currentUser) return <div className="p-10 font-bold text-slate-400">Select a case from the dashboard.</div>;

