import { Grievance, Status, User, UserRole, Department, Severity } from './types';

const GRIEVANCE_KEY = 'eduresolve_grievances_v2';
const USER_KEY = 'eduresolve_current_user';
const AUTH_KEY = 'eduresolve_is_authenticated';

export const MOCK_USERS: (User & { password: string })[] = [
  { id: 'STU-01', name: 'Student Alex', role: UserRole.STUDENT, email: 'student@bec.edu', password: 'password' },
  { id: 'ADM-PRIN', name: 'Principal Dr. Robert', role: UserRole.ADMIN, email: 'principal@bec.edu', password: 'password', department: Department.ADMINISTRATIVE },
  { id: 'STAFF-MESS', name: 'Mess Manager', role: UserRole.STAFF, email: 'mess@bec.edu', password: 'password', department: Department.MESS },
  { id: 'STAFF-HOSTEL', name: 'Chief Warden', role: UserRole.STAFF, email: 'hostel@bec.edu', password: 'password', department: Department.HOSTEL },
  { id: 'STAFF-INFRA', name: 'Estate Officer', role: UserRole.STAFF, email: 'infra@bec.edu', password: 'password', department: Department.INFRASTRUCTURE },
  { id: 'STAFF-TRANS', name: 'Transport Head', role: UserRole.STAFF, email: 'transport@bec.edu', password: 'password', department: Department.TRANSPORT },
];

export const getResponsibleStaffId = (dept: Department): string => {
  const staff = MOCK_USERS.find(u => u.department === dept);
  return staff ? staff.id : 'ADM-PRIN';
};

export const isAuthenticated = (): boolean => localStorage.getItem(AUTH_KEY) === 'true';

export const getCurrentUser = (): User | null => {
  if (!isAuthenticated()) return null;
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : null;
};

export const login = (userId: string, password: string): boolean => {
  const user = MOCK_USERS.find(u => (u.id === userId || u.email === userId) && u.password === password);
  if (user) {
    const { password: _, ...userData } = user;
    localStorage.setItem(USER_KEY, JSON.stringify(userData));
    localStorage.setItem(AUTH_KEY, 'true');
    window.dispatchEvent(new Event('storage'));
    return true;
  }
  return false;
};

export const logout = () => {
  localStorage.removeItem(USER_KEY);
  localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('storage'));
};

export const getGrievances = (): Grievance[] => {
  const data = localStorage.getItem(GRIEVANCE_KEY);
  let grievances: Grievance[] = data ? JSON.parse(data) : [];

  const ONE_WEEK_MS = 7 * 24 * 60 * 60 * 1000;
  const now = Date.now();
  let changed = false;

  grievances = grievances.map(g => {
    // Escalation check
    if (g.status !== Status.RESOLVED && g.status !== Status.CLOSED && (now - g.timestamp > ONE_WEEK_MS)) {
      if (!g.notificationsSent.some(n => n.message.includes('ESCALATED'))) {
        g.notificationsSent.push({
          type: 'alert',
          timestamp: now,
          message: 'CRITICAL: ESCALATED TO PRINCIPAL - Unresolved > 7 days'
        });
        g.assignedToId = 'ADM-PRIN';
        g.severity = Severity.CRITICAL;
        changed = true;
      }
    }
    return g;
  });

  if (changed) localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(grievances));
  return grievances;
};

// Logic to detect duplicates and return a Group ID
export const detectDuplicate = (newDescription: string, fingerprint: string): string | null => {
  const existing = getGrievances();
  const keywords = fingerprint.toLowerCase().split(',').map(k => k.trim());

  // Simple intersection logic for duplicate detection
  const match = existing.find(g => {
    if (g.status === Status.RESOLVED || g.status === Status.CLOSED) return false;
    const gKeywords = (g.fingerprint || "").toLowerCase().split(',');
    const intersection = keywords.filter(k => gKeywords.includes(k));
    return intersection.length >= 2; // Match if at least 2 key semantic terms align
  });

  return match ? match.groupId || match.id : null;
};

export const saveGrievance = (grievance: Grievance) => {
  const current = getGrievances();

  // Aggregation logic
  if (grievance.groupId) {
    const parentIdx = current.findIndex(g => g.id === grievance.groupId || g.groupId === grievance.groupId);
    if (parentIdx > -1) {
      current[parentIdx].clusterCount = (current[parentIdx].clusterCount || 1) + 1;
    }
  } else {
    grievance.groupId = grievance.id;
    grievance.clusterCount = 1;
  }

  localStorage.setItem(GRIEVANCE_KEY, JSON.stringify([...current, grievance]));
};

export const updateGrievance = (updatedG: Grievance) => {
  const current = getGrievances();
  const index = current.findIndex(g => g.id === updatedG.id);
  if (index > -1) {
    current[index] = updatedG;
    localStorage.setItem(GRIEVANCE_KEY, JSON.stringify(current));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

export const analyzeGrievanceState = async (text: string, history: { role: string; content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Full Conversation History: ${JSON.stringify(history)}\nNew User Message: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: { type: Type.BOOLEAN },
          followUpQuestion: { type: Type.STRING },
          department: { 
            type: Type.STRING, 
            description: "Must be: Mess, Hostel, Transport, Academic, Infrastructure, or Administrative" 
          },
          severity: { 
            type: Type.STRING, 
            description: "low, medium, high, or critical based on safety and number of people affected." 
          },
          summary: { type: Type.STRING },
          fingerprint: { 
            type: Type.STRING, 
            description: "3-4 unique lowercase keywords representing the CORE issue (e.g. 'water, leakage, hostel-a')" 
          }
        },
        required: ["isDetailedEnough", "followUpQuestion", "department", "severity", "summary", "fingerprint"],
      },
      systemInstruction: "You are an expert grievance classifier. Your job is to extract routing data and create a semantic 'fingerprint' of keywords for duplicate detection. Be strictly logical.",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getStaffAssistance = async (caseDescription: string, clusterCount: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Case: ${caseDescription}. This is reported by ${clusterCount} students.`,
    config: {
      systemInstruction: "Summarize this issue for a college manager. Suggest immediate resolution steps. Since multiple students are reporting, emphasize the impact level.",
    },
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState, getBotResponse } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS, detectDuplicate } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}. Briefly describe the issue you are facing.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [duplicateGroupId, setDuplicateGroupId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you provide more specific details?");
        } else {
          // Detect Duplicate
          const dupId = detectDuplicate(userMessage, result.fingerprint);
          setDuplicateGroupId(dupId);

          setState('REVIEW');
          const dupNotice = dupId ? "\n\n**Note:** Other students have reported a similar issue. We will group your report with theirs for faster resolution." : "";
          addBotMessage(`Summary Checklist:\n\n**Routing:** ${result.department} Office\n**Priority:** ${result.severity.toUpperCase()}\n\nReady to submit?${dupNotice}`);
        }
      } else if (state === 'REVIEW') {
        if (/yes|ok|correct|submit/i.test(userMessage)) {
          finalizeGrievance();
        } else {
          addBotMessage("Cancelled. What needs to be corrected?");
          setState('COLLECTING');
        }
      }
    } catch (e) {
      addBotMessage("I'm having trouble processing. Please try again in a moment.");
    } finally {
      setIsTyping(false);
    }
  };

  const finalizeGrievance = () => {
    const grievanceId = 'CMP-' + Math.floor(100 + Math.random() * 900);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary?.slice(0, 50) + '...',
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: false,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM' }],
      remarks: [],
      notificationsSent: [],
      fingerprint: analysis?.fingerprint,
      groupId: duplicateGroupId || undefined
    };

    saveGrievance(newGrievance);
    addBotMessage(`Submission Successful. ID: **${grievanceId}**.\n\nRouted to ${dept} department.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
      <div className="bg-slate-900 p-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center text-white font-bold">AI</div>
          <div>
             <h3 className="text-white font-bold text-sm">EduResolve Assistant</h3>
             <p className="text-slate-400 text-[10px] uppercase font-black tracking-widest">Intelligent Routing</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/30">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-5 rounded-2xl shadow-sm border ${msg.role === 'user' ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' : 'bg-white text-slate-900 border-slate-100 rounded-tl-none'}`}>
              <p className="text-sm font-medium leading-relaxed whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {isTyping && <div className="text-[10px] font-black uppercase text-indigo-500 animate-pulse">AI is analyzing context...</div>}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-6 bg-white border-t border-slate-100">
        <form onSubmit={handleSubmit} className="flex gap-4">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Complaint registered." : "Describe your issue..."}
            disabled={state === 'DONE' || isTyping}
            className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-bold text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
          />
          <button type="submit" disabled={!input.trim() || isTyping || state === 'DONE'} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-bold text-sm hover:bg-indigo-700 transition-all shadow-lg disabled:opacity-20">
            Send
          </button>
        </form>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import React, { useMemo } from 'react';
