      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
         {[
           { label: 'Pending', val: filtered.filter(g => g.status === Status.PENDING).length, color: 'text-amber-600' },
           { label: 'Critical', val: filtered.filter(g => g.severity === Severity.CRITICAL).length, color: 'text-red-600' },
           { label: 'Active Issues', val: filtered.filter(g => g.status !== Status.RESOLVED).length, color: 'text-indigo-600' },
