import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getGrievances, updateGrievance, getCurrentUser, MOCK_USERS, getResponsibleStaffId } from '../store';
// Fix: COLORS is exported from constants.tsx, not types.ts
import { Grievance, Status, UserRole, Department } from '../types';
import { COLORS } from '../constants';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [remarkInput, setRemarkInput] = useState('');
  const [statusInput, setStatusInput] = useState<Status | ''>('');
  const [reassignDept, setReassignDept] = useState<Department | ''>('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const id = location.state?.grievanceId;
    if (id) {
      const g = getGrievances().find(x => x.id === id);
      if (g) {
        setGrievance(g);
        setStatusInput(g.status);
      }
    }
  }, [location.state]);

  const handleUpdate = () => {
    if (!grievance || !currentUser) return;

    const now = Date.now();
    const updated: Grievance = { ...grievance };

    if (reassignDept && reassignDept !== grievance.department) {
      const newStaffId = getResponsibleStaffId(reassignDept);
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: `Reassigned from ${grievance.department} to ${reassignDept}. ${remarkInput}`,
        reassignedFrom: grievance.department,
        reassignedTo: reassignDept
      });
      updated.department = reassignDept;
      updated.assignedToId = newStaffId;
      updated.remarks.push(`REASSIGNED: ${remarkInput}`);
    } else {
      updated.status = (statusInput as Status) || updated.status;
      updated.lastStatusChange = now;
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: remarkInput
      });
      if (remarkInput) updated.remarks.push(remarkInput);
    }

    updateGrievance(updated);
    navigate('/dashboard');
  };

  const askAi = async () => {
    if (!grievance) return;
    setIsAiLoading(true);
    try {
      // Fix: Pass clusterCount as a number instead of a string instruction
      const res = await getStaffAssistance(grievance.description, grievance.clusterCount || 1);
      setAiResponse(res || 'No response from AI.');
    } catch (e) {
      setAiResponse('AI Service unavailable.');
    } finally {
      setIsAiLoading(false);
    }
  };

  if (!grievance || !currentUser) return <div className="p-10 font-bold text-slate-400">Select a case from the dashboard.</div>;

  const isEscalated = grievance.notificationsSent.some(n => n.message.includes('ESCALATED'));

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 pb-20">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm">
          <div className="flex justify-between items-start mb-6">
             <div className="space-y-1">
                <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Grievance Ticket</span>
                <h2 className="text-3xl font-bold text-slate-900">#{grievance.id}</h2>
             </div>
             <div className="flex flex-col items-end gap-2">
                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase ${COLORS.status[grievance.status]}`}>
                   {grievance.status}
                </span>
                {isEscalated && (
                  <span className="bg-red-600 text-white px-3 py-1 rounded-lg text-[10px] font-black animate-pulse">
                    ESCALATED TO PRINCIPAL
                  </span>
                )}
             </div>
          </div>

          <div className="bg-slate-50 rounded-2xl p-8 border border-slate-100">
             <p className="text-sm font-semibold text-slate-900 leading-relaxed mb-6">"{grievance.description}"</p>
             <div className="flex flex-wrap gap-4">
               {grievance.attachments?.map((at, i) => (
                 <a key={i} href={at.data} download={at.name} className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-slate-200 text-xs font-bold text-indigo-600 hover:bg-indigo-50">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M16 10l-4 4m0 0l-4-4m4 4V4" /></svg>
                    {at.name}
                 </a>
               ))}
             </div>
          </div>
        </div>

        <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm space-y-6">
           <h3 className="font-bold text-slate-900">Case Actions</h3>
           <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                 <label className="text-xs font-bold text-slate-500 uppercase">Update Status</label>
                 <select 
                    value={statusInput}
                    onChange={e => setStatusInput(e.target.value as Status)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                 >
                    {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
              </div>
              <div className="space-y-2">
                 <label className="text-xs font-bold text-slate-500 uppercase">Reassign Department</label>
                 <select 
                    value={reassignDept}
                    onChange={e => setReassignDept(e.target.value as Department)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                 >
                    <option value="">Keep in {grievance.department}</option>
                    {Object.values(Department).filter(d => d !== grievance.department).map(d => <option key={d} value={d}>{d}</option>)}
                 </select>
              </div>
           </div>
           <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase">Add Action Remark</label>
              <textarea 
                 value={remarkInput}
                 onChange={e => setRemarkInput(e.target.value)}
                 className="w-full bg-slate-50 border border-slate-200 rounded-xl px-6 py-4 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none min-h-[120px]"
                 placeholder="Type your resolution steps or reason for reassignment..."
              />
           </div>
           <button 
             onClick={handleUpdate}
             className="w-full py-4 bg-slate-950 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg"
           >
              Update Case
           </button>
        </div>
      </div>

      <div className="space-y-6">
         <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm h-full flex flex-col">
            <div className="flex items-center gap-3 mb-6">
               <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
               </div>
               <div>
                  <h4 className="font-bold text-slate-900">AI Assistance</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Staff Companion</p>
               </div>
            </div>

            <div className="flex-1 bg-slate-50 rounded-2xl p-6 overflow-y-auto mb-6 border border-slate-100 min-h-[200px]">
               {isAiLoading ? (
                 <div className="animate-pulse flex flex-col gap-3">
                   <div className="h-4 bg-slate-200 rounded w-full"></div>
                   <div className="h-4 bg-slate-200 rounded w-3/4"></div>
                   <div className="h-4 bg-slate-200 rounded w-5/6"></div>
                 </div>
               ) : (
                 <p className="text-sm font-medium text-slate-600 leading-relaxed italic">
                   {aiResponse || "Ask AI for a summary of this complaint and suggested resolution steps."}
                 </p>
               )}
            </div>

            <button 
              onClick={askAi}
              disabled={isAiLoading}
              className="w-full py-3 bg-indigo-50 text-indigo-700 font-bold rounded-xl text-sm border border-indigo-100 hover:bg-indigo-100 transition-all"
            >
               Summarize & Suggest
            </button>
         </div>

         <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm">
            <h4 className="font-bold text-slate-900 mb-4 text-sm">Action History</h4>
            <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2">
               {grievance.history.slice().reverse().map((h, i) => (
                 <div key={i} className="pl-4 border-l-2 border-indigo-100 py-1">
                    <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{new Date(h.timestamp).toLocaleString()}</p>
                    <p className="text-xs font-bold text-slate-900 mt-1 capitalize">{h.status}</p>
                    {h.remark && <p className="text-[11px] text-slate-500 mt-1 italic">"{h.remark}"</p>}
                 </div>
               ))}
            </div>
         </div>
      </div>
    </div>
  );
};

export default ManagementConsole;

import { GoogleGenAI, Type } from "@google/genai";

export const analyzeGrievanceState = async (text: string, history: { role: string; content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Full Conversation History: ${JSON.stringify(history)}\nNew User Message: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: { 
            type: Type.BOOLEAN,
            description: "True if the user has provided enough specifics (who/what/where/when) to form a complete report."
          },
          followUpQuestion: { 
            type: Type.STRING,
            description: "If details are missing, a short question to ask the user. Empty if detailed enough."
          },
          department: { 
            type: Type.STRING, 
            description: "Must be exactly one of: Mess, Hostel, Transport, Academic, Infrastructure, or Administrative" 
          },
          severity: { 
            type: Type.STRING, 
            description: "One of: low, medium, high, or critical." 
          },
          summary: { 
            type: Type.STRING,
            description: "A formal, objective one-sentence summary of the grievance that the user will review for accuracy. (e.g., 'Broken ceiling fan in Hostel B, Room 302, causing heat issues for 2 days.')"
          },
          fingerprint: { 
            type: Type.STRING, 
            description: "3-4 unique lowercase keywords for grouping (e.g. 'fan, electrical, hostel-b')" 
          }
        },
        required: ["isDetailedEnough", "followUpQuestion", "department", "severity", "summary", "fingerprint"],
      },
      systemInstruction: "You are an expert grievance classifier. Your primary goal is to determine if a complaint is complete and provide a formal summary that the user can verify. Use professional yet direct language.",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getStaffAssistance = async (caseDescription: string, clusterCount: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Case: ${caseDescription}. This is reported by ${clusterCount} students.`,
    config: {
      systemInstruction: "Summarize this issue for a college manager. Suggest immediate resolution steps. Since multiple students are reporting, emphasize the impact level.",
    },
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, MOCK_USERS, detectDuplicate } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}. Briefly describe the issue you are facing today.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [duplicateGroupId, setDuplicateGroupId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you provide more specific details about what happened and where?");
        } else {
          // Detect Duplicate
          const dupId = detectDuplicate(userMessage, result.fingerprint);
          setDuplicateGroupId(dupId);

          setState('REVIEW');
          const dupNotice = dupId ? "\n\n⚠️ **Note:** I've noticed a similar report already active. I will group your grievance with it to help the team solve it faster." : "";

          // Formal Summary Presentation
          addBotMessage(
            `I have compiled your grievance details. Please review this summary for accuracy:\n\n` +
            `> **" ${result.summary} "**\n\n` +
            `--- \n` +
            `• **Category:** ${result.department}\n` +
            `• **Priority:** ${result.severity.toUpperCase()}\n\n` +
            `**Is this information correct?** (Type 'Yes' to submit, or tell me what needs changing.)` +
            dupNotice
          );
        }
      } else if (state === 'REVIEW') {
        // Check for positive confirmation
        if (/yes|yep|correct|ok|confirm|submit|sure/i.test(userMessage)) {
          finalizeGrievance();
        } else if (/no|stop|cancel|wait|wrong|incorrect/i.test(userMessage)) {
          addBotMessage("Understood. Please provide the correct details, and I will update the summary.");
          setState('COLLECTING');
        } else {
          // If neither, treat as a correction and re-analyze
          addBotMessage("Got it. Updating the report with those details...");
          const updatedResult = await analyzeGrievanceState(userMessage, messages);
          setAnalysis(updatedResult);

          if (updatedResult.isDetailedEnough) {
            addBotMessage(
              `Updated Summary:\n\n` +
              `> **" ${updatedResult.summary} "**\n\n` +
              `Confirm submission?`
            );
          } else {
            addBotMessage(updatedResult.followUpQuestion || "Understood. Tell me more so I can fix the summary.");
            setState('COLLECTING');
          }
        }
      }
    } catch (e) {
      addBotMessage("I encountered an error processing that. Please try again or rephrase your concern.");
    } finally {
      setIsTyping(false);
    }
  };

  const finalizeGrievance = () => {
    const grievanceId = 'CMP-' + Math.floor(100 + Math.random() * 900);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary || "General Grievance",
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: false,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM', remark: 'Grievance verified and submitted by student via AI Chatbot.' }],
      remarks: [],
      notificationsSent: [],
      fingerprint: analysis?.fingerprint,
      groupId: duplicateGroupId || undefined
    };

    saveGrievance(newGrievance);
    addBotMessage(`✅ **Success!** Your grievance has been registered as **#${grievanceId}**.\n\nIt has been routed to the **${dept}** department for review. You can track progress in your dashboard.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
      <div className="bg-slate-900 p-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center text-white font-bold shadow-lg shadow-indigo-500/20">AI</div>
          <div>
             <h3 className="text-white font-bold text-sm tracking-tight">EduResolve Assistant</h3>
             <p className="text-slate-400 text-[10px] uppercase font-black tracking-widest">Intelligent Redressal</p>
          </div>
        </div>
        {state === 'REVIEW' && (
          <div className="bg-amber-500/10 border border-amber-500/20 px-3 py-1 rounded-full animate-pulse">
            <span className="text-amber-500 text-[10px] font-black uppercase tracking-widest">Awaiting Confirmation</span>
          </div>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/30">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-2xl shadow-sm border ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none shadow-indigo-100' 
                : 'bg-white text-slate-900 border-slate-100 rounded-tl-none'
            }`}>
              <p className="text-sm font-medium leading-relaxed whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-2 text-[10px] font-black uppercase text-indigo-500">
            <div className="flex gap-1">
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></span>
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '400ms'}}></span>
            </div>
            AI is organizing details...
          </div>
        )}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-6 bg-white border-t border-slate-100">
        <form onSubmit={handleSubmit} className="flex gap-4">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Ticket submitted successfully." : "Type your response here..."}
            disabled={state === 'DONE' || isTyping}
