/**
 * Virtual MongoDB Engine
 * Simulates MongoDB-style collection operations using localStorage persistence.
 */

class VirtualCollection<T extends { id: string }> {
  private key: string;

  constructor(collectionName: string) {
    this.key = `eduresolve_db_${collectionName}`;
  }

  private _getData(): T[] {
    const data = localStorage.getItem(this.key);
    return data ? JSON.parse(data) : [];
  }

  private _setData(data: T[]): void {
    localStorage.setItem(this.key, JSON.stringify(data));
    // Trigger real-time sync across tabs
    window.dispatchEvent(new Event('storage'));
    window.dispatchEvent(new CustomEvent('db-update', { detail: { collection: this.key } }));
  }

  async find(query: Partial<T> = {}): Promise<T[]> {
    await new Promise(r => setTimeout(r, 200)); // Simulate network latency
    const data = this._getData();
    return data.filter(item => {
      return Object.entries(query).every(([key, value]) => (item as any)[key] === value);
    });
  }

  async findOne(query: Partial<T>): Promise<T | null> {
    const results = await this.find(query);
    return results[0] || null;
  }

  async insertOne(doc: T): Promise<T> {
    await new Promise(r => setTimeout(r, 300));
    const data = this._getData();
    data.push(doc);
    this._setData(data);
    return doc;
  }

  async updateOne(query: Partial<T>, update: Partial<T>): Promise<boolean> {
    await new Promise(r => setTimeout(r, 250));
    const data = this._getData();
    const index = data.findIndex(item => {
      return Object.entries(query).every(([key, value]) => (item as any)[key] === value);
    });

    if (index !== -1) {
      data[index] = { ...data[index], ...update };
      this._setData(data);
      return true;
    }
    return false;
  }

  async countDocuments(query: Partial<T> = {}): Promise<number> {
    const results = await this.find(query);
    return results.length;
  }
}

