import { Grievance, Status, User, UserRole, Department, Severity } from './types';
import { db, seedDatabase } from './db';

const USER_KEY = 'eduresolve_current_user_v2';
const AUTH_KEY = 'eduresolve_is_authenticated_v2';

// Initialize the DB on load
seedDatabase();

export const isAuthenticated = (): boolean => localStorage.getItem(AUTH_KEY) === 'true';

export const getCurrentUser = (): User | null => {
  if (!isAuthenticated()) return null;
  const data = localStorage.getItem(USER_KEY);
  return data ? JSON.parse(data) : null;
};

export const login = async (userId: string, password: string): Promise<boolean> => {
  // Query Virtual MongoDB
  const user = await db.users.findOne({ id: userId, password });
  const userByEmail = !user ? await db.users.findOne({ email: userId, password }) : user;

  const targetUser = user || userByEmail;

  if (targetUser) {
    const { password: _, ...userData } = targetUser;
    localStorage.setItem(USER_KEY, JSON.stringify(userData));
    localStorage.setItem(AUTH_KEY, 'true');
    window.dispatchEvent(new Event('storage'));
    return true;
  }
  return false;
};

export const logout = () => {
  localStorage.removeItem(USER_KEY);
  localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('storage'));
};

export const getResponsibleStaffId = async (dept: Department): Promise<string> => {
  const staff = await db.users.findOne({ department: dept, role: UserRole.STAFF });
  return staff ? staff.id : 'ADM-PRIN';
};

export const getGrievances = async (): Promise<Grievance[]> => {
  const grievances = await db.grievances.find();

  const ONE_WEEK_MS = 7 * 24 * 60 * 60 * 1000;
  const now = Date.now();
  let updatedCount = 0;

  for (const g of grievances) {
    // Escalation check
    if (g.status !== Status.RESOLVED && g.status !== Status.CLOSED && (now - g.timestamp > ONE_WEEK_MS)) {
      if (!g.notificationsSent.some(n => n.message.includes('ESCALATED'))) {
        await db.grievances.updateOne({ id: g.id }, {
          severity: Severity.CRITICAL,
          assignedToId: 'ADM-PRIN',
          notificationsSent: [...g.notificationsSent, {
            type: 'alert',
            timestamp: now,
            message: 'CRITICAL: ESCALATED TO PRINCIPAL - Unresolved > 7 days'
          }]
        });
        updatedCount++;
      }
    }
  }

  return updatedCount > 0 ? await db.grievances.find() : grievances;
};

export const detectDuplicate = async (fingerprint: string): Promise<string | null> => {
  const grievances = await db.grievances.find();
  const keywords = fingerprint.toLowerCase().split(',').map(k => k.trim());

  const match = grievances.find(g => {
    if (g.status === Status.RESOLVED || g.status === Status.CLOSED) return false;
    const gKeywords = (g.fingerprint || "").toLowerCase().split(',');
    const intersection = keywords.filter(k => gKeywords.includes(k));
    return intersection.length >= 2;
  });

  return match ? (match.groupId || match.id) : null;
};

export const saveGrievance = async (grievance: Grievance) => {
  if (grievance.groupId) {
    const parent = await db.grievances.findOne({ id: grievance.groupId });
    if (parent) {
      await db.grievances.updateOne({ id: parent.id }, {
        clusterCount: (parent.clusterCount || 1) + 1
      });
    }
  } else {
    grievance.groupId = grievance.id;
    grievance.clusterCount = 1;
  }
  // Fix: Property 'db' does not exist on type 'db', removed extra '.db'
  await db.grievances.insertOne(grievance);
};

export const updateGrievance = async (updatedG: Grievance) => {
  await db.grievances.updateOne({ id: updatedG.id }, updatedG);
};

import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity, Attachment } from '../types';
// Fix: Removed MOCK_USERS as it is not exported from store
import { saveGrievance, getResponsibleStaffId, getCurrentUser, detectDuplicate } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Hello ${currentUser?.name}. Briefly describe the issue you are facing today.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [duplicateGroupId, setDuplicateGroupId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you provide more specific details about what happened and where?");
        } else {
          // Detect Duplicate
          // Fix: Expected 1 arguments, but got 2. detectDuplicate only takes fingerprint.
          // Also added await for async function.
          const dupId = await detectDuplicate(result.fingerprint);
          setDuplicateGroupId(dupId);

          setState('REVIEW');
          const dupNotice = dupId ? "\n\n⚠️ **Note:** I've noticed a similar report already active. I will group your grievance with it to help the team solve it faster." : "";

          // Formal Summary Presentation
          addBotMessage(
            `I have compiled your grievance details. Please review this summary for accuracy:\n\n` +
            `> **" ${result.summary} "**\n\n` +
            `--- \n` +
            `• **Category:** ${result.department}\n` +
            `• **Priority:** ${result.severity.toUpperCase()}\n\n` +
            `**Is this information correct?** (Type 'Yes' to submit, or tell me what needs changing.)` +
            dupNotice
          );
        }
      } else if (state === 'REVIEW') {
        // Check for positive confirmation
        if (/yes|yep|correct|ok|confirm|submit|sure/i.test(userMessage)) {
          // Fix: finalizeGrievance is async
          await finalizeGrievance();
        } else if (/no|stop|cancel|wait|wrong|incorrect/i.test(userMessage)) {
          addBotMessage("Understood. Please provide the correct details, and I will update the summary.");
          setState('COLLECTING');
        } else {
          // If neither, treat as a correction and re-analyze
          addBotMessage("Got it. Updating the report with those details...");
          const updatedResult = await analyzeGrievanceState(userMessage, messages);
          setAnalysis(updatedResult);

          if (updatedResult.isDetailedEnough) {
            addBotMessage(
              `Updated Summary:\n\n` +
              `> **" ${updatedResult.summary} "**\n\n` +
              `Confirm submission?`
            );
          } else {
            addBotMessage(updatedResult.followUpQuestion || "Understood. Tell me more so I can fix the summary.");
            setState('COLLECTING');
          }
        }
      }
    } catch (e) {
      addBotMessage("I encountered an error processing that. Please try again or rephrase your concern.");
    } finally {
      setIsTyping(false);
    }
  };

  // Fix: Changed to async to handle await for getResponsibleStaffId
  const finalizeGrievance = async () => {
    const grievanceId = 'CMP-' + Math.floor(100 + Math.random() * 900);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    // Fix: Await getResponsibleStaffId since it returns a Promise
    const staffId = await getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary || "General Grievance",
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: false,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM', remark: 'Grievance verified and submitted by student via AI Chatbot.' }],
      remarks: [],
      notificationsSent: [],
      fingerprint: analysis?.fingerprint,
      groupId: duplicateGroupId || undefined
    };

    await saveGrievance(newGrievance);
    addBotMessage(`✅ **Success!** Your grievance has been registered as **#${grievanceId}**.\n\nIt has been routed to the **${dept}** department for review. You can track progress in your dashboard.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[calc(100vh-12rem)] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
      <div className="bg-slate-900 p-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center text-white font-bold shadow-lg shadow-indigo-500/20">AI</div>
          <div>
             <h3 className="text-white font-bold text-sm tracking-tight">EduResolve Assistant</h3>
             <p className="text-slate-400 text-[10px] uppercase font-black tracking-widest">Intelligent Redressal</p>
          </div>
        </div>
        {state === 'REVIEW' && (
          <div className="bg-amber-500/10 border border-amber-500/20 px-3 py-1 rounded-full animate-pulse">
            <span className="text-amber-500 text-[10px] font-black uppercase tracking-widest">Awaiting Confirmation</span>
          </div>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/30">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-2xl shadow-sm border ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none shadow-indigo-100' 
                : 'bg-white text-slate-900 border-slate-100 rounded-tl-none'
            }`}>
              <p className="text-sm font-medium leading-relaxed whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-2 text-[10px] font-black uppercase text-indigo-500">
            <div className="flex gap-1">
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '200ms'}}></span>
              <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '400ms'}}></span>
            </div>
            AI is organizing details...
          </div>
        )}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-6 bg-white border-t border-slate-100">
        <form onSubmit={handleSubmit} className="flex gap-4">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Ticket submitted successfully." : "Type your response here..."}
            disabled={state === 'DONE' || isTyping}
            className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-bold text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none transition-all disabled:opacity-50"
          />
          <button 
            type="submit" 
            disabled={!input.trim() || isTyping || state === 'DONE'} 
            className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-bold text-sm hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 disabled:opacity-20"
          >
            Send
          </button>
        </form>
      </div>
    </div>
  );
};

