import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
// Fix: Removed MOCK_USERS as it is not exported from store
import { getGrievances, updateGrievance, getCurrentUser, getResponsibleStaffId } from '../store';
// Fix: COLORS is exported from constants.tsx, not types.ts
import { Grievance, Status, UserRole, Department } from '../types';
import { COLORS } from '../constants';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [remarkInput, setRemarkInput] = useState('');
  const [statusInput, setStatusInput] = useState<Status | ''>('');
  const [reassignDept, setReassignDept] = useState<Department | ''>('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const id = location.state?.grievanceId;
    if (id) {
      // Fix: Fetch grievances asynchronously
      const fetchAndSet = async () => {
        const all = await getGrievances();
        const g = all.find(x => x.id === id);
        if (g) {
          setGrievance(g);
          setStatusInput(g.status);
        }
      };
      fetchAndSet();
    }
  }, [location.state]);

  const handleUpdate = async () => {
    if (!grievance || !currentUser) return;

    const now = Date.now();
    const updated: Grievance = { ...grievance };

    if (reassignDept && reassignDept !== grievance.department) {
      // Fix: Await getResponsibleStaffId since it returns a Promise
      const newStaffId = await getResponsibleStaffId(reassignDept);
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: `Reassigned from ${grievance.department} to ${reassignDept}. ${remarkInput}`,
        reassignedFrom: grievance.department,
        reassignedTo: reassignDept
      });
      updated.department = reassignDept;
      updated.assignedToId = newStaffId;
      updated.remarks.push(`REASSIGNED: ${remarkInput}`);
    } else {
      updated.status = (statusInput as Status) || updated.status;
      updated.lastStatusChange = now;
      updated.history.push({
        status: updated.status,
        timestamp: now,
        userId: currentUser.id,
        remark: remarkInput
      });
      if (remarkInput) updated.remarks.push(remarkInput);
    }

    await updateGrievance(updated);
    navigate('/dashboard');
  };

  const askAi = async () => {
    if (!grievance) return;
    setIsAiLoading(true);
    try {
      // Fix: Pass clusterCount as a number
      const res = await getStaffAssistance(grievance.description, grievance.clusterCount || 1);
      setAiResponse(res || 'No response from AI.');
    } catch (e) {
      setAiResponse('AI Service unavailable.');
    } finally {
      setIsAiLoading(false);
    }
  };

  if (!grievance || !currentUser) return <div className="p-10 font-bold text-slate-400">Select a case from the dashboard.</div>;

  const isEscalated = grievance.notificationsSent.some(n => n.message.includes('ESCALATED'));

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 pb-20">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm">
          <div className="flex justify-between items-start mb-6">
             <div className="space-y-1">
                <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Grievance Ticket</span>
                <h2 className="text-3xl font-bold text-slate-900">#{grievance.id}</h2>
             </div>
             <div className="flex flex-col items-end gap-2">
                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase ${COLORS.status[grievance.status]}`}>
                   {grievance.status}
                </span>
                {isEscalated && (
                  <span className="bg-red-600 text-white px-3 py-1 rounded-lg text-[10px] font-black animate-pulse">
                    ESCALATED TO PRINCIPAL
                  </span>
                )}
             </div>
          </div>

          <div className="bg-slate-50 rounded-2xl p-8 border border-slate-100">
             <p className="text-sm font-semibold text-slate-900 leading-relaxed mb-6">"{grievance.description}"</p>
             <div className="flex flex-wrap gap-4">
               {grievance.attachments?.map((at, i) => (
                 <a key={i} href={at.data} download={at.name} className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-slate-200 text-xs font-bold text-indigo-600 hover:bg-indigo-50">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M16 10l-4 4m0 0l-4-4m4 4V4" /></svg>
                    {at.name}
                 </a>
               ))}
             </div>
          </div>
        </div>

        <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm space-y-6">
           <h3 className="font-bold text-slate-900">Case Actions</h3>
           <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                 <label className="text-xs font-bold text-slate-500 uppercase">Update Status</label>
                 <select 
                    value={statusInput}
                    onChange={e => setStatusInput(e.target.value as Status)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                 >
                    {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
              </div>
              <div className="space-y-2">
                 <label className="text-xs font-bold text-slate-500 uppercase">Reassign Department</label>
                 <select 
                    value={reassignDept}
                    onChange={e => setReassignDept(e.target.value as Department)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                 >
                    <option value="">Keep in {grievance.department}</option>
                    {Object.values(Department).filter(d => d !== grievance.department).map(d => <option key={d} value={d}>{d}</option>)}
                 </select>
              </div>
           </div>
           <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase">Add Action Remark</label>
              <textarea 
                 value={remarkInput}
                 onChange={e => setRemarkInput(e.target.value)}
                 className="w-full bg-slate-50 border border-slate-200 rounded-xl px-6 py-4 text-sm font-semibold text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none min-h-[120px]"
                 placeholder="Type your resolution steps or reason for reassignment..."
              />
           </div>
           <button 
             onClick={handleUpdate}
             className="w-full py-4 bg-slate-950 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg"
           >
              Update Case
           </button>
        </div>
      </div>

      <div className="space-y-6">
         <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm h-full flex flex-col">
            <div className="flex items-center gap-3 mb-6">
               <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
               </div>
               <div>
                  <h4 className="font-bold text-slate-900">AI Assistance</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Staff Companion</p>
               </div>
            </div>

            <div className="flex-1 bg-slate-50 rounded-2xl p-6 overflow-y-auto mb-6 border border-slate-100 min-h-[200px]">
               {isAiLoading ? (
                 <div className="animate-pulse flex flex-col gap-3">
                   <div className="h-4 bg-slate-200 rounded w-full"></div>
                   <div className="h-4 bg-slate-200 rounded w-3/4"></div>
                   <div className="h-4 bg-slate-200 rounded w-5/6"></div>
                 </div>
               ) : (
                 <p className="text-sm font-medium text-slate-600 leading-relaxed italic">
                   {aiResponse || "Ask AI for a summary of this complaint and suggested resolution steps."}
                 </p>
               )}
            </div>

            <button 
              onClick={askAi}
              disabled={isAiLoading}
              className="w-full py-3 bg-indigo-50 text-indigo-700 font-bold rounded-xl text-sm border border-indigo-100 hover:bg-indigo-100 transition-all"
            >
               Summarize & Suggest
            </button>
         </div>

         <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm">
            <h4 className="font-bold text-slate-900 mb-4 text-sm">Action History</h4>
            <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2">
               {grievance.history.slice().reverse().map((h, i) => (
                 <div key={i} className="pl-4 border-l-2 border-indigo-100 py-1">
                    <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{new Date(h.timestamp).toLocaleString()}</p>
                    <p className="text-xs font-bold text-slate-900 mt-1 capitalize">{h.status}</p>
                    {h.remark && <p className="text-[11px] text-slate-500 mt-1 italic">"{h.remark}"</p>}
                 </div>
               ))}
            </div>
         </div>
      </div>
    </div>
  );
};

export default ManagementConsole;

import React, { useMemo, useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { getGrievances, getCurrentUser } from '../store';
import { UserRole, Status, Department, Severity, Grievance } from '../types';
import { COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const user = getCurrentUser();
  const [allGrievances, setAllGrievances] = useState<Grievance[]>([]);
  const navigate = useNavigate();

  // Fix: Fetch grievances asynchronously
  useEffect(() => {
    const fetchGrievances = async () => {
      const data = await getGrievances();
      setAllGrievances(data);
    };
    fetchGrievances();
  }, []);

  // Filtering based on role
  const filtered = useMemo(() => {
    if (!user) return [];
    if (user.role === UserRole.ADMIN) return allGrievances;
    return allGrievances.filter(g => g.assignedToId === user.id || g.studentId === user.id);
  }, [allGrievances, user]);

  // Cluster/Trending Analysis
  const trending = useMemo(() => {
    const groups: Record<string, { id: string; title: string; count: number; dept: Department; severity: Severity }> = {};
    // Fix: allGrievances is now an array from state
    allGrievances.forEach(g => {
      if (g.status === Status.RESOLVED || g.status === Status.CLOSED) return;
      const gid = g.groupId || g.id;
      if (!groups[gid]) {
        groups[gid] = { id: g.id, title: g.title, count: 0, dept: g.department, severity: g.severity };
      }
      groups[gid].count++;
    });
    return Object.values(groups).sort((a, b) => b.count - a.count).slice(0, 3);
  }, [allGrievances]);

  if (!user) return null;

  return (
    <div className="space-y-8 pb-10">
      <div className="flex items-center justify-between">
         <div>
            <h2 className="text-4xl font-black text-slate-900 tracking-tighter">BEC Operations</h2>
            <p className="text-slate-500 font-bold text-sm uppercase tracking-widest mt-1">
              {user.role} Dashboard • {user.department || 'Global View'}
            </p>
         </div>
         {user.role === UserRole.STUDENT && (
           <Link to="/chatbot" className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold text-sm shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">
             Raise New Ticket
           </Link>
         )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
         {[
           { label: 'Pending', val: filtered.filter(g => g.status === Status.PENDING).length, color: 'text-amber-600' },
           { label: 'Critical', val: filtered.filter(g => g.severity === Severity.CRITICAL).length, color: 'text-red-600' },
           { label: 'Active Issues', val: filtered.filter(g => g.status !== Status.RESOLVED).length, color: 'text-indigo-600' },
           { label: 'Resolved', val: filtered.filter(g => g.status === Status.RESOLVED).length, color: 'text-emerald-600' },
         ].map((s, i) => (
           <div key={i} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{s.label}</span>
              <span className={`text-4xl font-black ${s.color}`}>{s.val}</span>
           </div>
         ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
           <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="font-bold text-slate-900">Recent Assignments</h3>
           </div>
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase">
                  <tr>
                    <th className="px-6 py-4">ID</th>
                    <th className="px-6 py-4">Issue</th>
                    <th className="px-6 py-4">Impact</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4"></th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-slate-100">
                  {filtered.length === 0 ? (
                    <tr><td colSpan={5} className="p-10 text-center text-slate-400 font-bold">No active tickets found.</td></tr>
                  ) : (
                    filtered.slice(0, 6).map(g => (
                      <tr key={g.id} className="hover:bg-slate-50 transition-all group">
                        <td className="px-6 py-4 text-xs font-bold text-indigo-600">#{g.id}</td>
                        <td className="px-6 py-4">
                           <p className="text-sm font-bold text-slate-900 truncate max-w-[150px]">{g.title}</p>
                           <p className="text-[10px] text-slate-400 uppercase font-black">{g.department}</p>
                        </td>
                        <td className="px-6 py-4">
                           <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase ${COLORS.severity[g.severity]}`}>
                             {g.severity}
                           </span>
                        </td>
                        <td className="px-6 py-4">
                           <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase ${COLORS.status[g.status]}`}>
                             {g.status}
                           </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                           <button onClick={() => navigate('/manage', { state: { grievanceId: g.id } })} className="text-xs font-black text-indigo-600 hover:underline opacity-0 group-hover:opacity-100">VIEW</button>
                        </td>
                      </tr>
                    ))
                  )}
               </tbody>
             </table>
           </div>
        </div>

        <div className="space-y-6">
           <div className="bg-slate-900 rounded-3xl p-6 text-white shadow-xl">
              <h3 className="text-xs font-black uppercase tracking-widest text-indigo-400 mb-4">Trending Issues</h3>
              <div className="space-y-4">
                 {trending.map((t, i) => (
                   <div key={i} className="bg-white/10 p-4 rounded-2xl border border-white/10 hover:bg-white/20 transition-all cursor-pointer">
                      <div className="flex justify-between items-start mb-2">
                        <span className="text-[10px] font-black uppercase text-indigo-300">{t.dept}</span>
                        <span className="bg-indigo-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">+{t.count} REPORTS</span>
                      </div>
                      <p className="text-sm font-bold truncate">{t.title}</p>
