/**
 * AI PIPELINE SIMULATOR
 * Mimics: DistilBERT Classification + SBERT Embedding + FAISS Similarity Check
 */
export const runAIPipeline = async (complaintText: string, existingContext: string = "") => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `PROCESS NEW COMPLAINT:
    Text: "${complaintText}"
    Context: "${existingContext}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          category: { 
            type: Type.STRING, 
            description: "Classification: Mess, Hostel, Infrastructure, Academic, Administrative, Transport" 
          },
          priority: { 
            type: Type.STRING, 
            description: "Risk Level: low, medium, high, critical" 
          },
          sentiment_score: { type: Type.NUMBER },
          summary: { type: Type.STRING },
          is_duplicate: { type: Type.BOOLEAN },
          group_id: { type: Type.STRING, description: "UUID of existing cluster if similarity > 0.85" },
          auto_route_staff_id: { type: Type.STRING },
          urgent_keywords: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          }
        },
        required: ["category", "priority", "summary", "is_duplicate"],
      },
      systemInstruction: `You are the AI Pipeline for EduResolve. 
      Act as a combination of a DistilBERT classifier and a Sentence-Transformer embedding engine.
      - Calculate priority based on keywords like 'safety', 'fire', 'harassment' or 'illness'.
      - If multiple complaints exist about the same physical object or event, set is_duplicate to true.`,
    },
  });

  return JSON.parse(response.text || '{}');
};

