import { fetchGrievances } from '../store';
import { Grievance, Severity, Department } from '../types';

const AdminAnalytics: React.FC = () => {
  const [data, setData] = useState<Grievance[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchGrievances().then(res => {
      setData(res);
      setLoading(false);
    });
  }, []);

  const stats = {
    total: data.length,
    critical: data.filter(g => g.severity === Severity.CRITICAL).length,
    resolved: data.filter(g => g.status === 'resolved').length,
    avgTime: '1.8 Days'
  };

  const chartData = Object.values(Department).map(dept => ({
    name: dept,
    count: data.filter(g => g.department === dept).length
  }));

  const priorityData = Object.values(Severity).map(sev => ({
    name: sev,
    value: data.filter(g => g.severity === sev).length
  }));

  const COLORS = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#64748b'];

  if (loading) return <div className="p-10 text-slate-400 font-bold animate-pulse">Querying Analytics Engine...</div>;

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Total Volume', value: stats.total, color: 'text-indigo-600' },
          { label: 'Critical Risk', value: stats.critical, color: 'text-red-600' },
          { label: 'Resolution Rate', value: `${((stats.resolved/stats.total || 0)*100).toFixed(0)}%`, color: 'text-emerald-600' },
          { label: 'Avg Turnaround', value: stats.avgTime, color: 'text-slate-900' },
        ].map((s, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-1">{s.label}</p>
            <p className={`text-3xl font-black ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black uppercase text-slate-400 tracking-widest mb-8">Departmental Distribution</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} style={{fontSize: '10px', fontWeight: 'bold'}} />
                <YAxis axisLine={false} tickLine={false} style={{fontSize: '10px'}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                <Bar dataKey="count" fill="#6366f1" radius={[6, 6, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-black uppercase text-slate-400 tracking-widest mb-8">Priority Segmentation</h3>
          <div className="h-80 flex flex-col items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={priorityData} innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="value">
                  {priorityData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex gap-4 mt-4">
              {priorityData.map((p, i) => (
                <div key={i} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[i]}}></div>
                  <span className="text-[10px] font-black uppercase text-slate-500">{p.name}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminAnalytics;

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import GrievanceChatbot from './components/GrievanceChatbot';
import GrievanceTracker from './components/GrievanceTracker';
import Dashboard from './components/Dashboard';
import ManagementConsole from './components/ManagementConsole';
import UserManagement from './components/UserManagement';
import AdminSettings from './components/AdminSettings';
import AdminAnalytics from './components/AdminAnalytics';
import Login from './components/Login';
import Landing from './components/Landing';
import { isAuthenticated, getCurrentUser } from './store';
import { UserRole } from './types';

const ProtectedRoute: React.FC<{ children: React.ReactNode; roles?: UserRole[] }> = ({ children, roles }) => {
  const user = getCurrentUser();
  if (!isAuthenticated()) {
    return <Navigate to="/login" replace />;
  }
  if (roles && user && !roles.includes(user.role)) {
    return <Navigate to="/dashboard" replace />;
  }
  return <>{children}</>;
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Landing />} />
          <Route path="/login" element={<Login />} />

          <Route path="/dashboard" element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } />

          <Route path="/chatbot" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceChatbot />
            </ProtectedRoute>
          } />

          <Route path="/track" element={
            <ProtectedRoute roles={[UserRole.STUDENT]}>
              <GrievanceTracker />
            </ProtectedRoute>
          } />

          <Route path="/manage" element={
            <ProtectedRoute roles={[UserRole.STAFF, UserRole.ADMIN]}>
              <ManagementConsole />
            </ProtectedRoute>
          } />

          <Route path="/users" element={
            <ProtectedRoute roles={[UserRole.ADMIN]}>
              <UserManagement />
            </ProtectedRoute>
          } />

          <Route path="/analytics" element={
            <ProtectedRoute roles={[UserRole.ADMIN]}>
              <AdminAnalytics />
            </ProtectedRoute>
          } />

          <Route path="/settings" element={
            <ProtectedRoute roles={[UserRole.ADMIN]}>
              <AdminSettings />
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

