 */
// Fix: Renamed runAIPipeline to analyzeGrievanceState and updated parameters/schema
export const analyzeGrievanceState = async (complaintText: string, history: ChatMessage[]) => {
  const historyText = history.map(m => `${m.role}: ${m.content}`).join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `HISTORY:
    ${historyText}

    NEW USER INPUT:
    "${complaintText}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: { 
            type: Type.BOOLEAN, 
            description: "True if what, where, and when are clearly stated." 
          },
          followUpQuestion: { 
            type: Type.STRING, 
            description: "Friendly question to ask if details are missing." 
          },
          summary: { 
            type: Type.STRING, 
            description: "Concise 1-sentence summary of the grievance." 
          },
          department: { 
            type: Type.STRING, 
            description: "Category: Technical, Infrastructure, Academic, Administrative, Mess, Hostel, Transport" 
          },
          severity: { 
            type: Type.STRING, 
            description: "Risk: low, medium, high, critical" 
          },
          fingerprint: { 
            type: Type.STRING, 
            description: "3-5 semantic keywords for similarity detection." 
          }
        },
        required: ["isDetailedEnough", "summary", "department", "severity", "fingerprint"],
      },
      systemInstruction: `You are the EduResolve Grievance Analyst. 
      Your goal is to extract structured data from student complaints.
      - If details like location or specific event time are missing, set isDetailedEnough to false.
      - Map departments to: Technical, Infrastructure, Academic, Administrative, Mess, Hostel, Transport.
      - Map severity based on safety and academic impact.`,
    },
  });

  return JSON.parse(response.text || '{}');
};

