// Fix: Added saveGrievance function
export const saveGrievance = async (grievance: Grievance) => {
  return await db.grievances.insertOne(grievance);
};

// Fix: Added updateGrievance function that handles the whole object
export const updateGrievance = async (grievance: Grievance) => {
  const { id, ...update } = grievance;
  return await db.grievances.updateOne({ id }, update);
};

export const updateGrievanceStatus = async (id: string, status: string, remark: string) => {
  // Update local DB for demo
  const g = await db.grievances.findOne({ id });
  if (g) {
    const updated = {
      ...g,
      status: status as Status,
      remarks: remark ? [...g.remarks, remark] : g.remarks,
      history: [...g.history, { status: status as Status, timestamp: Date.now(), userId: 'SYSTEM', remark }]
    };
    await db.grievances.updateOne({ id }, updated);
  }
  return await endpoints.grievances.updateStatus(id, status, remark);
};

// Fix: Added getResponsibleStaffId function
export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  if (staff.length > 0) return staff[0].id;

  const admin = await db.users.findOne({ role: UserRole.ADMIN });
  return admin?.id || 'SYSTEM';
};

// Fix: Added detectDuplicate function
export const detectDuplicate = async (fingerprint?: string): Promise<string | null> => {
  if (!fingerprint) return null;
  const keywords = fingerprint.toLowerCase().split(' ');
  const all = await db.grievances.find();

  const match = all.find(g => {
    if (g.status === Status.CLOSED || g.status === Status.RESOLVED) return false;
    const gFingerprint = (g.fingerprint || '').toLowerCase();
    return keywords.some(k => gFingerprint.includes(k));
  });

  return match ? (match.groupId || match.id) : null;
};

export const isAdmin = () => getCurrentUser()?.role === UserRole.ADMIN;
export const isStaff = () => getCurrentUser()?.role === UserRole.STAFF;

