export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  if (staff.length > 0) return staff[0].id;

  const admin = await db.users.findOne({ role: UserRole.ADMIN });
  return admin?.id || 'SYSTEM';
};

// Fix: Added detectDuplicate function
export const detectDuplicate = async (fingerprint?: string): Promise<string | null> => {
  if (!fingerprint) return null;
  const keywords = fingerprint.toLowerCase().split(' ');
  const all = await db.grievances.find();

  const match = all.find(g => {
    if (g.status === Status.CLOSED || g.status === Status.RESOLVED) return false;
    const gFingerprint = (g.fingerprint || '').toLowerCase();
    return keywords.some(k => gFingerprint.includes(k));
  });

  return match ? (match.groupId || match.id) : null;
};

