/**
 * DATABASE INTERFACE
 */
interface DatabaseProvider {
  find<T>(collection: string, query?: any): Promise<T[]>;
  findOne<T>(collection: string, query: any): Promise<T | null>;
  insertOne<T>(collection: string, doc: T): Promise<T>;
  updateOne<T>(collection: string, query: any, update: any): Promise<boolean>;
}

/**
 * PRODUCTION: MongoDB Atlas Data API Provider
 * This connects to a real MongoDB instance via HTTPS.
 */
class MongoDBAtlasProvider implements DatabaseProvider {
  private endpoint: string;
  private apiKey: string;

  constructor() {
    // In production, these are injected via your build environment
    this.endpoint = localStorage.getItem('PROD_DB_URL') || '/api/mongodb';
    this.apiKey = localStorage.getItem('PROD_DB_KEY') || '';
  }

  private async request(action: string, params: any) {
    // If you are using a real Node.js backend, you'd fetch from your own domain
    const response = await fetch(`${this.endpoint}/${action}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'api-key': this.apiKey, // Only for Atlas Data API
      },
      body: JSON.stringify(params),
    });
    return response.json();
  }

  async find<T>(collection: string, query: any = {}): Promise<T[]> {
    const result = await this.request('find', { collection, filter: query });
    return result.documents || [];
  }

  async findOne<T>(collection: string, query: any): Promise<T | null> {
    const result = await this.request('findOne', { collection, filter: query });
    return result.document || null;
  }

  async insertOne<T>(collection: string, doc: T): Promise<T> {
    await this.request('insertOne', { collection, document: doc });
    return doc;
  }

  async updateOne<T>(collection: string, query: any, update: any): Promise<boolean> {
    const result = await this.request('updateOne', { collection, filter: query, update: { $set: update } });
    return result.matchedCount > 0;
  }
}

/**
 * LOCAL: Virtual Browser MongoDB (Development Only)
 */
class LocalStorageProvider implements DatabaseProvider {
  private prefix = 'eduresolve_db_';

  private _get(collection: string): any[] {
    const data = localStorage.getItem(this.prefix + collection);
    return data ? JSON.parse(data) : [];
  }

  private _set(collection: string, data: any[]) {
    localStorage.setItem(this.prefix + collection, JSON.stringify(data));
    window.dispatchEvent(new Event('storage'));
  }

  async find<T>(collection: string, query: any = {}): Promise<T[]> {
    await new Promise(r => setTimeout(r, 150));
    const data = this._get(collection);
    return data.filter(item => 
      Object.entries(query).every(([k, v]) => item[k] === v)
    );
  }

  async findOne<T>(collection: string, query: any): Promise<T | null> {
    const results = await this.find<T>(collection, query);
    return results[0] || null;
  }

  async insertOne<T>(collection: string, doc: T): Promise<T> {
    const data = this._get(collection);
    data.push(doc);
    this._set(collection, data);
    return doc;
  }

  async updateOne<T>(collection: string, query: any, update: any): Promise<boolean> {
    const data = this._get(collection);
    const idx = data.findIndex(item => 
      Object.entries(query).every(([k, v]) => item[k] === v)
    );
    if (idx !== -1) {
      data[idx] = { ...data[idx], ...update };
      this._set(collection, data);
      return true;
    }
    return false;
  }
}

// Current Mode: 'LOCAL' | 'PRODUCTION'
const MODE = localStorage.getItem('DB_MODE') || 'LOCAL';
const provider: DatabaseProvider = MODE === 'PRODUCTION' ? new MongoDBAtlasProvider() : new LocalStorageProvider();

