import React, { useMemo, useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { getGrievances, getCurrentUser } from '../store';
import { UserRole, Status, Department, Severity, Grievance } from '../types';
import { COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const user = getCurrentUser();
  const [allGrievances, setAllGrievances] = useState<Grievance[]>([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchGrievances = async () => {
      const data = await getGrievances();
      setAllGrievances(data);
    };
    fetchGrievances();
  }, []);

  const filtered = useMemo(() => {
    if (!user) return [];
    if (user.role === UserRole.ADMIN) return allGrievances;
    return allGrievances.filter(g => g.assignedToId === user.id || g.studentId === user.id);
  }, [allGrievances, user]);

  const trending = useMemo(() => {
    const groups: Record<string, { id: string; title: string; count: number; dept: Department; severity: Severity }> = {};
    allGrievances.forEach(g => {
      if (g.status === Status.RESOLVED || g.status === Status.CLOSED) return;
      const gid = g.groupId || g.id;
      if (!groups[gid]) {
        groups[gid] = { id: g.id, title: g.title, count: 0, dept: g.department, severity: g.severity };
      }
      groups[gid].count++;
    });
    return Object.values(groups).sort((a, b) => b.count - a.count).slice(0, 3);
  }, [allGrievances]);

  if (!user) return null;

  return (
    <div className="space-y-12 pb-16">
      <div className="flex items-center justify-between">
         <div className="space-y-1">
            <h2 className="text-5xl font-black text-slate-900 tracking-tighter">BIT Oversight Dashboard</h2>
            <div className="flex items-center gap-3">
              <span className="bg-slate-100 px-3 py-1 rounded text-[10px] font-black text-slate-500 uppercase tracking-widest border border-slate-200">
                Administrative Session
              </span>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-[0.2em]">
                {user.role} Authorization • {user.department || 'Global Institution View'}
              </p>
            </div>
         </div>
         {user.role === UserRole.STUDENT && (
           <Link to="/chatbot" className="bg-slate-950 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-slate-200 hover:bg-slate-800 transition-all">
             Initialize Grievance
           </Link>
         )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
         {[
           { label: 'Pending Review', val: filtered.filter(g => g.status === Status.PENDING).length, color: 'text-amber-600' },
           { label: 'Critical Escalations', val: filtered.filter(g => g.severity === Severity.CRITICAL).length, color: 'text-red-600' },
           { label: 'Total Operations', val: filtered.filter(g => g.status !== Status.RESOLVED).length, color: 'text-indigo-600' },
           { label: 'Closed Cases', val: filtered.filter(g => g.status === Status.RESOLVED).length, color: 'text-emerald-600' },
         ].map((s, i) => (
           <div key={i} className="bg-white p-8 rounded-[32px] border border-slate-200 shadow-sm flex flex-col justify-center">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">{s.label}</span>
              <span className={`text-5xl font-black ${s.color} tracking-tighter`}>{s.val}</span>
           </div>
         ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        <div className="lg:col-span-2 bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
           <div className="p-10 border-b border-slate-100 flex items-center justify-between">
              <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">Active Operation Queue</h3>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Real-time Data Stream</span>
           </div>
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <tr>
                    <th className="px-10 py-6">ID</th>
                    <th className="px-10 py-6">Subject Matter</th>
                    <th className="px-10 py-6">Operational Impact</th>
                    <th className="px-10 py-6">Process Status</th>
                    <th className="px-10 py-6"></th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-slate-100">
                  {filtered.length === 0 ? (
                    <tr><td colSpan={5} className="p-20 text-center text-slate-300 font-bold uppercase tracking-widest text-xs">No administrative active tickets.</td></tr>
                  ) : (
                    filtered.slice(0, 6).map(g => (
                      <tr key={g.id} className="hover:bg-slate-50 transition-all group">
                        <td className="px-10 py-6 text-xs font-black text-indigo-600">#{g.id}</td>
                        <td className="px-10 py-6">
                           <p className="text-sm font-black text-slate-900 truncate max-w-[200px] mb-1">{g.title}</p>
                           <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{g.department}</p>
                        </td>
                        <td className="px-10 py-6">
                           <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${COLORS.severity[g.severity]}`}>
                             {g.severity}
                           </span>
                        </td>
                        <td className="px-10 py-6">
                           <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${COLORS.status[g.status]}`}>
                             {g.status}
                           </span>
                        </td>
                        <td className="px-10 py-6 text-right">
                           <button onClick={() => navigate('/manage', { state: { grievanceId: g.id } })} className="text-[10px] font-black text-indigo-600 hover:bg-indigo-50 px-4 py-2 rounded-lg transition-all opacity-0 group-hover:opacity-100 uppercase tracking-widest">Process Case</button>
                        </td>
                      </tr>
                    ))
                  )}
               </tbody>
             </table>
           </div>
        </div>

        <div className="space-y-8">
           <div className="bg-slate-950 rounded-[40px] p-10 text-white shadow-2xl">
              <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400 mb-8">Institutional Trends</h3>
              <div className="space-y-6">
                 {trending.map((t, i) => (
                   <div key={i} className="bg-white/5 p-6 rounded-3xl border border-white/5 hover:bg-white/10 transition-all cursor-pointer">
                      <div className="flex justify-between items-start mb-3">
                        <span className="text-[9px] font-black uppercase text-indigo-300 tracking-widest">{t.dept}</span>
                        <span className="bg-indigo-500 text-white text-[9px] px-3 py-1 rounded-full font-black tracking-widest">+{t.count} INCIDENTS</span>
                      </div>
                      <p className="text-sm font-black truncate text-slate-100">{t.title}</p>
                   </div>
                 ))}
                 {trending.length === 0 && <p className="text-[10px] text-white/40 italic font-black uppercase tracking-widest">No active trends detected.</p>}
              </div>
           </div>

           <div className="bg-white rounded-[40px] p-10 border border-slate-200 shadow-sm">
              <h3 className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] mb-6">Service Level Metrics</h3>
              <div className="space-y-4">
                 <div className="flex justify-between text-xs font-black text-slate-900 uppercase tracking-widest">
                    <span>Average Resolution</span>
                    <span className="text-indigo-600">2.4 Operational Days</span>
                 </div>
                 <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div className="bg-indigo-600 h-full w-3/4 rounded-full"></div>
                 </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

