      <div className="bg-white w-full max-w-lg rounded-[40px] shadow-2xl border border-slate-200 overflow-hidden">
        <div className="p-12 flex flex-col items-center justify-center gap-6 bg-white border-b border-slate-50">
          <img 
            src="https://mental-orange-t56uiavvis-coyn24mp43.edgeone.app/logo_cropped.png" 
            alt="KIT Institutional Logo" 
            className="h-32 w-auto object-contain drop-shadow-md" 
          />
          <div className="text-center space-y-1">
            <h1 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Kangeyam Institute of Technology</h1>
            <p className="text-[11px] font-bold text-indigo-600 uppercase tracking-[0.3em]">Unified Redressal Portal</p>
          </div>
        </div>

        <div className="p-12 space-y-10">
          <div className="text-center space-y-2">
            <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Portal Access</h2>
            <p className="text-slate-500 font-semibold text-sm">Authenticating session for {roleName}</p>
