                placeholder="••••••••"
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-bold text-slate-900 placeholder:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                required
              />
            </div>

            {error && <p className="text-red-600 text-[10px] font-black uppercase text-center bg-red-50 py-4 rounded-2xl border border-red-100">{error}</p>}

            <button 
