import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, detectDuplicate } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Greetings, ${currentUser?.name}. I am the KIT Grievance Assistant. Briefly describe the concern you wish to document today.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [duplicateGroupId, setDuplicateGroupId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Could you provide additional specifics regarding the incident and its location?");
        } else {
          const dupId = await detectDuplicate(result.fingerprint);
          setDuplicateGroupId(dupId);
          setState('REVIEW');

          const dupNotice = dupId ? "\n\n⚠️ **Operational Note:** A similar concern is currently being processed. I will group your submission to facilitate a coordinated institutional response." : "";

          addBotMessage(
            `I have synthesized your report. Please confirm the accuracy of this summary:\n\n` +
            `> **Summary:** ${result.summary}\n\n` +
            `• **Department:** ${result.department}\n` +
            `• **Priority:** ${result.severity.toUpperCase()}\n\n` +
            `Type **'Confirm'** to proceed with institutional filing, or provide corrections.` +
            dupNotice
          );
        }
      } else if (state === 'REVIEW') {
        if (/confirm|yes|correct|ok|submit/i.test(userMessage)) {
          await finalizeGrievance();
        } else {
          addBotMessage("Updating session records with new information...");
          const updatedResult = await analyzeGrievanceState(userMessage, messages);
          setAnalysis(updatedResult);

          if (updatedResult.isDetailedEnough) {
            addBotMessage(`Revised Summary: ${updatedResult.summary}\n\nConfirm submission?`);
          } else {
            addBotMessage(updatedResult.followUpQuestion || "Please elaborate further to finalize the report.");
            setState('COLLECTING');
          }
        }
      }
    } catch (e) {
      addBotMessage("An error occurred within the AI processing engine. Please rephrase your concern.");
    } finally {
      setIsTyping(false);
    }
  };

  const finalizeGrievance = async () => {
    const grievanceId = 'CMP-' + Math.floor(1000 + Math.random() * 9000);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = await getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary || "General Concern",
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: false,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM', remark: 'AI Verification complete. Institutional filing registered.' }],
      remarks: [],
      notificationsSent: [],
      fingerprint: analysis?.fingerprint,
      groupId: duplicateGroupId || undefined
    };

    await saveGrievance(newGrievance);
    addBotMessage(`✅ **Filing Complete.** Reference ID: **#${grievanceId}**.\n\nYour concern has been successfully routed to the **${dept}** division. Institutional tracking is now active.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-3xl mx-auto h-[calc(100vh-14rem)] bg-white rounded-lg border border-slate-200 shadow-sm flex flex-col overflow-hidden animate-in fade-in duration-500">
      <div className="bg-slate-50 p-5 border-b border-slate-200 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center text-white text-xs font-bold">AI</div>
          <div>
             <h3 className="text-sm font-bold text-slate-900">KIT AI Redressal Assistant</h3>
             <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Intelligent Case Mapping</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-white">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] px-4 py-3 rounded-lg text-sm leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white shadow-sm' 
                : 'bg-slate-100 text-slate-800'
            }`}>
              {msg.content}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-2 text-[10px] font-bold text-indigo-500 uppercase tracking-widest animate-pulse">
            Processing institutional data...
          </div>
        )}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-5 border-t border-slate-100 bg-slate-50/30">
        <form onSubmit={handleSubmit} className="flex gap-3">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Case filed successfully." : "Describe your concern in detail..."}
            disabled={state === 'DONE' || isTyping}
            className="flex-1 bg-white border border-slate-200 rounded-lg px-4 py-2.5 text-sm font-medium text-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none transition-all disabled:opacity-50"
          />
          <button 
            type="submit" 
            disabled={!input.trim() || isTyping || state === 'DONE'} 
            className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-bold text-sm hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100 disabled:opacity-50"
          >
            Send
          </button>
        </form>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

