import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser, detectDuplicate } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Identity verified. Greetings, ${currentUser?.name}. I am the AI Redressal Assistant. Briefly state the institutional concern you wish to report.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [duplicateGroupId, setDuplicateGroupId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Institutional protocols require more specific details. Please clarify the location and nature of the concern.");
        } else {
          const dupId = await detectDuplicate(result.fingerprint);
          setDuplicateGroupId(dupId);
          setState('REVIEW');

          const dupNotice = dupId ? "\n\n**Oversight Note:** A similar concern has been detected in the system. Your report will be grouped for coordinated resolution." : "";

          addBotMessage(
            `Data extraction complete. Please verify this synthesis:\n\n` +
            `**Summary:** ${result.summary}\n` +
            `**Dept:** ${result.department}\n` +
            `**Impact:** ${result.severity.toUpperCase()}\n\n` +
            `Type **'Confirm'** to finalize filing, or provide corrections.` +
            dupNotice
          );
        }
      } else if (state === 'REVIEW') {
        if (/confirm|yes|correct|ok|submit/i.test(userMessage)) {
          await finalizeGrievance();
        } else {
          addBotMessage("Re-analyzing session context...");
          const updatedResult = await analyzeGrievanceState(userMessage, messages);
          setAnalysis(updatedResult);

          if (updatedResult.isDetailedEnough) {
            addBotMessage(`Revised Summary: ${updatedResult.summary}\n\nProceed with filing?`);
          } else {
            addBotMessage(updatedResult.followUpQuestion || "Please elaborate further to satisfy filing requirements.");
            setState('COLLECTING');
          }
        }
      }
    } catch (e) {
      addBotMessage("Infrastructure error: AI processing gateway timeout. Please retry.");
    } finally {
      setIsTyping(false);
    }
  };

  const finalizeGrievance = async () => {
    const grievanceId = 'KIT-' + Math.floor(1000 + Math.random() * 9000);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = await getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary || "General Concern",
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: false,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM', remark: 'AI Verification complete. Case registered.' }],
      remarks: [],
      notificationsSent: [],
      fingerprint: analysis?.fingerprint,
      groupId: duplicateGroupId || undefined
    };

    await saveGrievance(newGrievance);
    addBotMessage(`✅ **Filing Verified.** Reference: **#${grievanceId}**.\n\nYour report has been successfully routed to the **${dept}** division. Monitoring is now active.`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-12rem)] bg-white rounded-lg border border-slate-200 shadow-sm flex flex-col overflow-hidden animate-in fade-in duration-500">
      <div className="bg-slate-50 p-5 border-b border-slate-200 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center text-white text-[11px] font-bold">AI</div>
          <div>
             <h3 className="text-sm font-bold text-slate-900">UGRS AI Assistant</h3>
             <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Intelligent Filing Engine</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <div className="w-2 h-2 bg-emerald-500 rounded-full"></div>
           <span className="text-[10px] font-bold text-slate-400 uppercase">Operational</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-[#FCFDFF]">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[75%] px-5 py-3.5 rounded-lg text-[14px] leading-relaxed font-medium shadow-sm border ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white border-indigo-500' 
                : 'bg-white text-slate-700 border-slate-100'
            }`}>
              {msg.content}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex items-center gap-3 p-4 bg-slate-50/50 rounded-lg w-fit border border-slate-100 animate-pulse">
             <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-100"></div>
                <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-200"></div>
             </div>
             <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Processing Data...</span>
          </div>
        )}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-6 border-t border-slate-100 bg-white">
        <form onSubmit={handleSubmit} className="flex gap-3">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Filing successfully completed." : "Enter concern details..."}
            disabled={state === 'DONE' || isTyping}
            className="flex-1 bg-slate-50 border border-slate-200 rounded-lg px-5 py-3 text-sm font-medium text-slate-900 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all placeholder:text-slate-400 disabled:opacity-50"
          />
          <button 
            type="submit" 
            disabled={!input.trim() || isTyping || state === 'DONE'} 
            className="bg-indigo-600 text-white px-8 py-3 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100 disabled:opacity-50"
          >
            Send
          </button>
        </form>
      </div>
    </div>
  );
};

