              to={item.path}
              className={`flex items-center gap-3 px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
                location.pathname === item.path 
                  ? 'bg-indigo-50 text-indigo-700' 
                  : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'
              }`}
            >
              {item.icon}
              {item.label}
            </Link>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-100 bg-slate-50/30">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-3 px-4 py-2 text-sm font-semibold text-slate-500 hover:text-red-600 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            Logout
          </button>
        </div>
      </aside>

      {/* Main Container */}
      <div className="flex-1 pl-[260px] flex flex-col min-h-screen">
        <header className="h-[72px] bg-white border-b border-slate-200 px-8 flex items-center justify-between sticky top-0 z-20">
          <h2 className="text-xl font-bold text-slate-800">Welcome, {currentUser.name}</h2>
          <div className="flex items-center gap-6">
            <button className="relative text-slate-400 hover:text-indigo-600 transition-colors">
              <ICONS.Notification />
              <span className="absolute -top-1 -right-1 w-4 h-4 bg-slate-900 text-white text-[10px] flex items-center justify-center rounded-full border-2 border-white font-bold">2</span>
            </button>
            <div className="h-8 w-px bg-slate-200"></div>
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 bg-slate-100 rounded-full flex items-center justify-center text-xs font-bold text-slate-600 uppercase">
                {currentUser.name.split(' ').map(n => n[0]).join('')}
              </div>
              <span className="text-sm font-bold text-slate-700">{currentUser.name}</span>
            </div>
          </div>
        </header>

        <main className="p-8 max-w-7xl mx-auto w-full flex-1">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useMemo, useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { getGrievances, getCurrentUser } from '../store';
import { UserRole, Status, Grievance } from '../types';
import { COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const user = getCurrentUser();
  const [grievances, setGrievances] = useState<Grievance[]>([]);
  const navigate = useNavigate();

  useEffect(() => {
    getGrievances().then(setGrievances);
  }, []);

  const studentData = useMemo(() => {
    const mine = grievances.filter(g => g.studentId === user?.id);
    return {
      total: mine.length,
      pending: mine.filter(g => g.status === Status.PENDING).length,
      progress: mine.filter(g => g.status === Status.IN_PROGRESS).length,
      resolved: mine.filter(g => g.status === Status.RESOLVED).length,
      list: mine.slice(0, 3)
    };
  }, [grievances, user]);

  const staffData = useMemo(() => {
    const assigned = grievances.filter(g => g.assignedToId === user?.id || user?.role === UserRole.ADMIN);
    return {
      assigned: assigned.length,
      pending: assigned.filter(g => g.status === Status.PENDING).length,
      overdue: 0, // Mock for visual
      resolved: assigned.filter(g => g.status === Status.RESOLVED).length,
      list: assigned.slice(0, 5)
    };
  }, [grievances, user]);

  if (!user) return null;

  // --- STUDENT VIEWPORT ---
  if (user.role === UserRole.STUDENT) {
    return (
      <div className="space-y-8 animate-in fade-in duration-500">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <StatCard label="Total Complaints" value={studentData.total} subtext="All time" icon="📄" />
          <StatCard label="Pending" value={studentData.pending} subtext="Awaiting assignment" icon="🕒" color="text-amber-500" />
          <StatCard label="In Progress" value={studentData.progress} subtext="Being handled" icon="📈" color="text-indigo-600" />
          <StatCard label="Resolved" value={studentData.resolved} subtext="Completed" icon="✅" color="text-emerald-600" />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <ActionCard 
            title="Raise New Grievance" 
            desc="Submit a new complaint about academic, infrastructure, or administrative issues"
            btnText="Create Complaint"
            onClick={() => navigate('/chatbot')}
            icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>}
          />
          <ActionCard 
            title="View All Complaints" 
            desc="Track and manage all your submitted complaints in one place"
            btnText="View Complaints"
            onClick={() => navigate('/track')}
            variant="outline"
            icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>}
          />
        </div>

        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-5 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-900">Recent Complaints</h3>
            <Link to="/track" className="text-sm font-bold text-slate-500 hover:text-indigo-600">View All</Link>
          </div>
          <div className="divide-y divide-slate-50">
            {studentData.list.map(g => (
              <div key={g.id} className="px-6 py-5 hover:bg-slate-50 transition-colors">
                <div className="flex justify-between items-start mb-2">
                   <h4 className="font-bold text-slate-800 text-base">{g.title || 'Untitled Grievance'}</h4>
                   <span className={COLORS.status[g.status]}>{g.status}</span>
                </div>
                <p className="text-sm text-slate-500 line-clamp-2 mb-3">{g.description}</p>
                <div className="flex items-center gap-3 text-xs text-slate-400 font-medium">
                   <span>{g.id}</span>
                   <span>&bull;</span>
                   <span>{g.department}</span>
                   <span>&bull;</span>
                   <span>{new Date(g.timestamp).toLocaleDateString()}</span>
                </div>
              </div>
            ))}
            {studentData.list.length === 0 && (
               <div className="p-10 text-center text-slate-400 italic">No recent activity found.</div>
            )}
          </div>
        </div>
      </div>
    );
  }

  // --- STAFF/ADMIN VIEWPORT ---
  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
         <div>
            <h2 className="text-2xl font-bold text-slate-900 tracking-tight">{user.role} Dashboard</h2>
            <p className="text-sm text-slate-500 mt-1">Manage and resolve assigned complaints</p>
         </div>
         {user.role === UserRole.ADMIN && (
            <Link to="/analytics" className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg shadow-indigo-100">View Analytics</Link>
         )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard label="Assigned" value={staffData.assigned} subtext="Total assigned to you" icon="📄" />
        <StatCard label="Pending" value={staffData.pending} subtext="Needs attention" icon="🕒" color="text-amber-500" />
        <StatCard label="Overdue" value={staffData.overdue} subtext="Past deadline" icon="⚠️" color="text-red-600" />
        <StatCard label="Resolved" value={staffData.resolved} subtext="This month" icon="✅" color="text-emerald-600" />
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-6 py-5 border-b border-slate-100">
          <h3 className="font-bold text-slate-900">My Worklist</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50 text-xs font-bold text-slate-400 uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">ID</th>
                <th className="px-6 py-4">Title</th>
                {user.role === UserRole.ADMIN && <th className="px-6 py-4">Student</th>}
                <th className="px-6 py-4">Priority</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Created</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {staffData.list.map(g => (
                <tr key={g.id} className="text-sm hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-900">{g.id}</td>
                  <td className="px-6 py-4 font-medium text-slate-700 max-w-xs truncate">{g.title || g.description}</td>
                  {user.role === UserRole.ADMIN && <td className="px-6 py-4 text-slate-500 font-medium">STU-{g.studentId.split('-').pop()}</td>}
                  <td className="px-6 py-4"><span className={COLORS.severity[g.severity]}>{g.severity}</span></td>
                  <td className="px-6 py-4"><span className={COLORS.status[g.status]}>{g.status}</span></td>
                  <td className="px-6 py-4 text-slate-400 font-medium">{new Date(g.timestamp).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => navigate('/manage', { state: { grievanceId: g.id } })} className="text-indigo-600 hover:text-indigo-800 font-bold transition-colors">Resolve &rarr;</button>
                  </td>
                </tr>
              ))}
              {staffData.list.length === 0 && (
                <tr><td colSpan={user.role === UserRole.ADMIN ? 7 : 6} className="px-6 py-20 text-center text-slate-400 font-medium italic">No complaints assigned to your queue.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

