import React, { useState, useMemo, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getGrievances, getCurrentUser } from '../store';
import { Grievance, Status, Department } from '../types';
import { ICONS, COLORS } from '../constants';

const GrievanceTracker: React.FC = () => {
  const user = getCurrentUser();
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [grievances, setGrievances] = useState<Grievance[]>([]);

  useEffect(() => {
    getGrievances().then(setGrievances);
  }, []);

  const complaints = useMemo(() => {
    if (!user) return [];
    return grievances.filter(g => g.studentId === user.id).filter(g => {
      const matchSearch = g.id.toLowerCase().includes(search.toLowerCase()) || (g.title || '').toLowerCase().includes(search.toLowerCase());
      const matchStatus = filterStatus === 'all' || g.status === filterStatus;
      const matchCategory = filterCategory === 'all' || g.department === filterCategory;
      return matchSearch && matchStatus && matchCategory;
    });
  }, [user, grievances, search, filterStatus, filterCategory]);

  if (!user) return null;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">My Complaints</h2>
          <p className="text-sm text-slate-500 mt-1">Track and manage all your submitted complaints</p>
        </div>
        <button 
          onClick={() => navigate('/chatbot')}
          className="flex items-center gap-2 bg-slate-950 text-white px-5 py-2.5 rounded-lg font-bold text-sm hover:bg-slate-800 transition-all shadow-lg"
        >
          <ICONS.Raise />
          New Complaint
        </button>
      </div>

      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-8">
        <h3 className="font-bold text-slate-800 text-sm uppercase tracking-wider">Filters</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="relative">
             <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none text-slate-400">
               <ICONS.Search />
             </div>
             <input 
                type="text" 
                placeholder="Search complaints..." 
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="w-full bg-[#F9FAFB] border border-slate-200 rounded-lg pl-12 pr-4 py-2.5 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" 
             />
          </div>
          <select 
            value={filterStatus}
            onChange={e => setFilterStatus(e.target.value)}
            className="bg-[#F9FAFB] border border-slate-200 rounded-lg px-4 py-2.5 text-sm font-medium text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
          >
            <option value="all">All Status</option>
            {Object.values(Status).map(s => <option key={s} value={s}>{s.replace('-', ' ')}</option>)}
          </select>
          <select 
             value={filterCategory}
             onChange={e => setFilterCategory(e.target.value)}
             className="bg-[#F9FAFB] border border-slate-200 rounded-lg px-4 py-2.5 text-sm font-medium text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
          >
            <option value="all">All Categories</option>
            {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50 border-b border-slate-100 text-xs font-bold text-slate-400 uppercase tracking-wider">
              <tr>
                <th className="px-8 py-4">ID</th>
                <th className="px-8 py-4">Title</th>
                <th className="px-8 py-4">Category</th>
                <th className="px-8 py-4">Priority</th>
                <th className="px-8 py-4">Status</th>
                <th className="px-8 py-4">Created</th>
                <th className="px-8 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {complaints.map(g => (
                <tr key={g.id} className="hover:bg-slate-50 transition-all text-sm">
                  <td className="px-8 py-5 font-bold text-slate-900">{g.id}</td>
                  <td className="px-8 py-5 font-medium text-slate-600 truncate max-w-[200px]">{g.title || 'General Complaint'}</td>
                  <td className="px-8 py-5"><span className="px-2.5 py-1 bg-slate-100 text-slate-700 rounded-md text-[11px] font-bold">{g.department}</span></td>
                  <td className="px-8 py-5"><span className={COLORS.severity[g.severity]}>{g.severity}</span></td>
                  <td className="px-8 py-5"><span className={COLORS.status[g.status]}>{g.status}</span></td>
                  <td className="px-8 py-5 text-slate-400 font-medium">{new Date(g.timestamp).toLocaleDateString()}</td>
                  <td className="px-8 py-5 text-right">
                    <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-indigo-600 transition-colors">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                    </button>
                  </td>
                </tr>
              ))}
              {complaints.length === 0 && (
                <tr><td colSpan={7} className="px-8 py-20 text-center text-slate-400 italic">No complaints matching your filters.</td></tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="p-6 bg-slate-50/30 border-t border-slate-100 flex items-center justify-between">
           <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Showing {complaints.length} of {complaints.length} complaints</p>
           <div className="flex gap-2">
              <button disabled className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-400 opacity-50">Previous</button>
              <button disabled className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-400 opacity-50">Next</button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default GrievanceTracker;

import React, { useEffect, useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { getGrievances } from '../store';
import { Grievance, Severity, Department, Status } from '../types';

const AdminAnalytics: React.FC = () => {
  const [data, setData] = useState<Grievance[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getGrievances().then(res => {
      setData(res);
      setLoading(false);
    });
  }, []);

  const stats = useMemo(() => ({
    total: data.length,
    unresolved: data.filter(g => g.status !== Status.RESOLVED && g.status !== Status.CLOSED).length,
  }), [data]);

  const chartData = useMemo(() => Object.values(Department).map(dept => ({
    name: dept.split(' ')[0], // Short name
    count: data.filter(g => g.department === dept).length
  })).filter(d => d.count > 0), [data]);

  const priorityData = useMemo(() => Object.values(Severity).map(sev => ({
    name: sev.charAt(0).toUpperCase() + sev.slice(1),
    value: data.filter(g => g.severity === sev).length
  })).filter(d => d.value > 0), [data]);

  const PIE_COLORS = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#64748b'];

  if (loading) return <div className="p-10 text-center animate-pulse text-indigo-600 font-bold">Generating Analytics Engine...</div>;

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
      <div className="flex items-end justify-between">
        <div className="space-y-1">
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Admin Dashboard</h2>
          <p className="text-slate-500 font-medium">Monitor and resolve institution-wide grievances.</p>
        </div>
        <div className="flex gap-4">
           <div className="bg-white border border-slate-200 rounded-xl px-8 py-4 shadow-sm text-center min-w-[140px]">
              <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-1">Total Tickets</p>
              <p className="text-2xl font-bold text-indigo-600">{stats.total}</p>
           </div>
           <div className="bg-white border border-slate-200 rounded-xl px-8 py-4 shadow-sm text-center min-w-[140px]">
              <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-1">Unresolved</p>
              <p className="text-2xl font-bold text-orange-600">{stats.unresolved}</p>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-8">
          <h3 className="font-bold text-slate-800 text-lg">Grievances by Department</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} style={{fontSize: '11px', fontWeight: 600, fill: '#64748b'}} />
                <YAxis axisLine={false} tickLine={false} style={{fontSize: '11px', fill: '#64748b'}} />
                <Tooltip cursor={{fill: '#F8FAFC'}} contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-8">
          <h3 className="font-bold text-slate-800 text-lg">Severity Distribution</h3>
          <div className="h-[300px] flex items-center relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={priorityData} innerRadius={70} outerRadius={100} paddingAngle={8} dataKey="value">
                  {priorityData.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={PIE_COLORS[index % PIE_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex flex-col gap-4 absolute right-4 top-1/2 -translate-y-1/2">
              {priorityData.map((p, i) => (
                <div key={i} className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: PIE_COLORS[i]}}></div>
                  <span className="text-xs font-bold text-slate-600">{p.name} ({p.value})</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
          <h3 className="font-bold text-slate-900 text-lg">Recent Grievances</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
