import { Grievance, User, UserRole, Department, Status } from './types';
import api, { endpoints } from './services/api';
import { db } from './db';

// State management
let currentUser: User | null = null;

// Custom event to notify components when session changes
const SESSION_CHANGE_EVENT = 'kit_session_change';

export const setSession = (user: User, token: string) => {
  currentUser = user;
  localStorage.setItem('access_token', token);
  localStorage.setItem('user_profile', JSON.stringify(user));
  // Dispatch event so all components know to re-render
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
};

export const getCurrentUser = (): User | null => {
  if (currentUser) return currentUser;
  const saved = localStorage.getItem('user_profile');
  if (saved) {
    currentUser = JSON.parse(saved);
    return currentUser;
  }
  return null;
};

export const isAuthenticated = (): boolean => {
  return !!localStorage.getItem('access_token');
};

export const login = async (userIdOrEmail: string, password: string): Promise<boolean> => {
  // 1. Clear any existing stale data first
  localStorage.clear();
  currentUser = null;

  // 2. Lookup in our database
  let user = await db.users.findOne({ id: userIdOrEmail, password });
  if (!user) {
    user = await db.users.findOne({ email: userIdOrEmail, password });
  }

  if (user) {
    const { password: _, ...profile } = user;
    setSession(profile as User, 'mock-jwt-token-' + Date.now());
    return true;
  }
  return false;
};

export const logout = () => {
  currentUser = null;
  localStorage.clear();
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
  window.location.href = '/#/login';
};

// Hook-like listener for session changes
export const subscribeToSession = (callback: () => void) => {
  window.addEventListener(SESSION_CHANGE_EVENT, callback);
  window.addEventListener('storage', callback); // For multi-tab support
  return () => {
    window.removeEventListener(SESSION_CHANGE_EVENT, callback);
    window.removeEventListener('storage', callback);
  };
};

/**
 * DATA ACTIONS
 */
export const fetchGrievances = async (): Promise<Grievance[]> => {
  try {
    const res = await db.grievances.find();
    return res || [];
  } catch (e) {
    console.error("Database fetch failed", e);
    return [];
  }
};

export const getGrievances = fetchGrievances;

export const saveGrievance = async (grievance: Grievance) => {
  return await db.grievances.insertOne(grievance);
};

export const updateGrievance = async (grievance: Grievance) => {
  const { id, ...update } = grievance;
  return await db.grievances.updateOne({ id }, update);
};

export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  if (staff.length > 0) return staff[0].id;

  const admin = await db.users.findOne({ role: UserRole.ADMIN });
  return admin?.id || 'SYSTEM';
};

export const detectDuplicate = async (fingerprint?: string): Promise<string | null> => {
  if (!fingerprint) return null;
  const keywords = fingerprint.toLowerCase().split(' ');
  const all = await db.grievances.find();

  const match = all.find(g => {
    if (g.status === Status.CLOSED || g.status === Status.RESOLVED) return false;
    const gFingerprint = (g.fingerprint || '').toLowerCase();
    return keywords.some(k => gFingerprint.includes(k));
  });

  return match ? (match.groupId || match.id) : null;
};

